_SESSIONS_PERSIST_PATH: Path = Path.home() / ".solace" / "sessions.json"


def _persist_sessions() -> None:
    """Write _SESSIONS to disk so dedup survives server restarts."""
    try:
        with _SESSIONS_LOCK:
            snapshot = dict(_SESSIONS)
        _SESSIONS_PERSIST_PATH.parent.mkdir(parents=True, exist_ok=True)
        _SESSIONS_PERSIST_PATH.write_text(
            json.dumps(snapshot, indent=2), encoding="utf-8"
        )
    except OSError:
        pass


def _load_sessions_from_disk() -> None:
    """Restore persisted sessions on startup; drop any whose process has exited."""
    try:
        raw = json.loads(_SESSIONS_PERSIST_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return
    if not isinstance(raw, dict):
        return
    alive: dict[str, dict] = {}
    for sid, sess in raw.items():
        try:
            pid = int(sess.get("pid", 0) or 0)
        except (TypeError, ValueError):
            continue
        if pid <= 0:
            continue
        try:
            os.kill(pid, 0)  # check if process is still running
            alive[sid] = sess
        except OSError:
            pass  # process gone — drop the stale session
    with _SESSIONS_LOCK:
        _SESSIONS.update(alive)


def _allocate_head_hidden_display() -> str:
    xvfb = shutil.which("Xvfb")
    if not xvfb:
        raise FileNotFoundError("Xvfb is required for head-hidden browser sessions")
    for display_number in range(99, 130):
        socket_path = Path(f"/tmp/.X11-unix/X{display_number}")
        if not socket_path.exists():
            return f":{display_number}"
    raise FileNotFoundError("no free Xvfb display available for head-hidden browser session")


def _cleanup_session_sidecars(session: dict[str, Any]) -> None:
    xvfb_pid = int(session.get("xvfb_pid", 0) or 0)
    if xvfb_pid <= 0:
        return
    try:
        os.kill(xvfb_pid, signal.SIGTERM)
    except OSError:
        return

    def _force_kill() -> None:
        time.sleep(2)
        try:
            os.kill(xvfb_pid, signal.SIGKILL)
        except OSError:
            pass

    threading.Thread(target=_force_kill, daemon=True).start()


def _terminate_browser_pid(pid: int) -> bool:
    if pid <= 0:
        return False
    try:
        os.kill(pid, signal.SIGTERM)
    except OSError:
        return False

    def _force_kill() -> None:
        time.sleep(3)
        try:
            os.kill(pid, signal.SIGKILL)
        except OSError:
            pass

    threading.Thread(target=_force_kill, daemon=True).start()
    return True


