def _triage_single_email(email: dict[str, Any], config: dict[str, bool]) -> dict[str, Any]:
    """Deterministic triage — no LLM required. Returns action + confidence."""
    sender: str = email.get("sender", "").lower()
    subject: str = email.get("subject", "").lower()
    action = "keep"
    confidence = 0

    if config.get("archive_newsletters") and (
        "newsletter" in sender or "noreply" in sender or "no-reply" in sender
    ):
        action = "archive"
        confidence = 90
    elif config.get("archive_social_notifications") and any(d in sender for d in SOCIAL_DOMAINS):
        action = "archive"
        confidence = 85
    elif config.get("snooze_follow_ups") and (
        "following up" in subject or "reminder" in subject or "follow-up" in subject
    ):
        action = "snooze"
        confidence = 80
    elif config.get("label_receipts") and (
        "receipt" in subject or "order" in subject or "invoice" in subject
    ):
        action = "label"
        confidence = 75

    return {
        "email_id": email.get("id", ""),
        "sender": email.get("sender", ""),
        "subject": email.get("subject", ""),
        "action": action,
        "confidence": confidence,
    }


def _utc_isoformat(timestamp: float) -> str:
    return datetime.fromtimestamp(timestamp, tz=timezone.utc).isoformat().replace("+00:00", "Z")


def _sha256_text(value: str) -> str:
    return hashlib.sha256(value.encode("utf-8")).hexdigest()


def _decimal_2(value: Any) -> str:
    return str(Decimal(str(value)).quantize(Decimal("0.01")))


def _tracker_sha256(value: Any) -> str:
    text = str(value).strip()
    if not text:
        return ""
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def _tracker_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")


def _tracker_decimal_str(value: Any) -> str:
    return str(Decimal(str(value)).quantize(Decimal("0.00")))


def _tracker_parse_non_negative_decimal(value: Any, field_name: str) -> tuple[Optional[Decimal], Optional[str]]:
    try:
        decimal_value = Decimal(str(value))
    except InvalidOperation:
        return None, f"{field_name} must be a non-negative decimal"
    if decimal_value < Decimal("0"):
        return None, f"{field_name} must be a non-negative decimal"
    return decimal_value, None


def _tracker_parse_int(value: Any, field_name: str, minimum: int) -> tuple[Optional[int], Optional[str]]:
    if not isinstance(value, int) or isinstance(value, bool) or value < minimum:
        if minimum == 0:
            return None, f"{field_name} must be a non-negative integer"
        if minimum == 1:
            return None, f"{field_name} must be an integer >= 1"
        return None, f"{field_name} must be an integer >= {minimum}"
    return value, None


def _tracker_parse_bool(value: Any, field_name: str) -> tuple[Optional[bool], Optional[str]]:
    if not isinstance(value, bool):
        return None, f"{field_name} must be a boolean"
    return value, None


def _call_openrouter_chat(user_message: str, api_key: str) -> tuple[str, str, int, str]:
    """Call OpenRouter with meta-llama/llama-3.3-70b-instruct.

    Returns (reply_text, model_used, tokens_used, cost_usd_str).
    Raises urllib.error.URLError or OSError on network failure — caller must handle.
    """
    payload = json.dumps({
        "model": "meta-llama/llama-3.3-70b-instruct",
        "messages": [
            {
                "role": "system",
                "content": (
                    "You are YinYang, the Solace Hub AI assistant. "
                    "You help users automate browser tasks, manage schedules, "
                    "and understand their evidence trail. "
                    "Be concise (max 3 sentences). "
                    "NEVER suggest actions outside Solace Hub scope."
                ),
            },
            {"role": "user", "content": user_message},
        ],
        "max_tokens": 256,
    }).encode()
    req = urllib.request.Request(
        "https://openrouter.ai/api/v1/chat/completions",
        data=payload,
        headers={
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        },
        method="POST",
    )
    with urllib.request.urlopen(req, timeout=15) as resp:
        data = json.loads(resp.read())
    reply_text = data["choices"][0]["message"]["content"].strip()
    usage = data.get("usage", {})
    tokens_used = usage.get("total_tokens", 0)
    # Approximate cost: $0.59 / 1M tokens (Llama 3.3 70B on Together/OpenRouter)
    cost_usd = str(Decimal(str(tokens_used)) * Decimal("0.00000059"))
    model_used = data.get("model", "meta-llama/llama-3.3-70b-instruct")
    return reply_text, model_used, tokens_used, cost_usd


def _action_preview_text(action_type: str, app_id: str, params: dict[str, Any]) -> str:
    resource_names = ", ".join(sorted(str(key) for key in params.keys())) or "no explicit resources"
    app_label = app_id or "unknown-app"
    return f"Approve {action_type} for {app_label}; affects {resource_names}."


def _build_action_preview(action_type: str, app_id: str, params: dict[str, Any], action_class: str) -> dict[str, Any]:
    return {
        "preview_text": _action_preview_text(action_type, app_id, params),
        "estimated_cost": str(Decimal("0.00")),
        "affected_resources": sorted(str(key) for key in params.keys()),
        "reversal_possible": action_class == "B",
    }


def _action_state_copy(action: dict[str, Any]) -> dict[str, Any]:
    return json.loads(json.dumps(action, sort_keys=True))


def _build_action_hash(
    action_type: str,
    params: dict[str, Any],
    app_id: str,
    oauth3_token_id: str,
) -> str:
    payload = {
        "action_type": action_type,
        "app_id": app_id,
        "oauth3_token_id": oauth3_token_id,
        "params": params,
    }
    return hashlib.sha256(json.dumps(payload, sort_keys=True).encode()).hexdigest()


def _create_pending_action_record(
    action_type: str,
    params: dict[str, Any],
    app_id: str,
    oauth3_token_id: str,
    now_ts: float,
) -> dict[str, Any]:
    action_class = ACTION_CLASSES.get(action_type, "B")
    preview = _build_action_preview(action_type, app_id, params, action_class)
    return {
        "action_id": str(uuid.uuid4()),
        "action_type": action_type,
        "class": action_class,
        "params": params,
        "app_id": app_id,
        "oauth3_token_id": oauth3_token_id,
        "action_hash": _build_action_hash(action_type, params, app_id, oauth3_token_id),
        "status": "PENDING_APPROVAL",
        "preview": preview,
        "cooldown_ends_at": now_ts + COOLDOWN_SECONDS[action_class],
        "approval_expires_at": now_ts + COOLDOWN_SECONDS[action_class] + 86400,  # 24h sign-off window
        "created_at": now_ts,
    }


def _pending_action_list_item(action: dict[str, Any], now_ts: float) -> dict[str, Any]:
    cooldown_end = float(action.get("cooldown_ends_at", now_ts))
    remaining = max(0.0, cooldown_end - now_ts)
    return {
        "action_id": action.get("action_id") or action.get("preview_id", ""),
        "action_type": action["action_type"],
        "class": action["class"],
        "status": action["status"],
        "preview_summary": action.get("preview", {}).get("preview_text", action.get("preview_text", "")),
        "cooldown_ends_at": _utc_isoformat(cooldown_end),
        "cooldown_remaining_seconds": int(remaining),
        "app_id": action.get("app_id", ""),
    }

