# ---------------------------------------------------------------------------
# Token utilities — theorem: plaintext token must never reach disk.
# ---------------------------------------------------------------------------
def generate_token() -> str:
    """Generate a cryptographically random URL-safe token (48 chars min)."""
    return secrets.token_urlsafe(32)


def token_hash(token: str) -> str:
    """SHA-256 hex digest of token. The only form written to disk."""
    return hashlib.sha256(token.encode()).hexdigest()


def write_port_lock(port: int, t_hash: str, pid: int) -> None:
    """Write port.lock with token_sha256 and pid — plaintext token NEVER stored."""
    PORT_LOCK_PATH.parent.mkdir(parents=True, exist_ok=True)
    PORT_LOCK_PATH.write_text(json.dumps({
        "port": port,
        "token_sha256": t_hash,
        "pid": pid,
    }))


def delete_port_lock() -> None:
    """Remove port.lock on clean shutdown."""
    try:
        PORT_LOCK_PATH.unlink()
    except FileNotFoundError:
        pass


@functools.lru_cache(maxsize=1)
def _detect_available_agents():
    """Detect AI coding CLIs available on PATH. Absence is valid state."""
    found: dict[str, str] = {}
    for name, binary in CLI_AGENT_CANDIDATES.items():
        path = shutil.which(binary)
        if path is not None:
            found[name] = path
    return found


def _default_model_for_agent(agent_name: str) -> str:
    """Return the default model for a supported CLI agent."""
    return DEFAULT_MODELS.get(agent_name, "unknown")


def _build_cli_command(agent_name: str, executable: str, prompt: str, model: Optional[str] = None) -> list[str]:
    """Build a shell-free subprocess argv for one CLI agent."""
    if agent_name == "claude":
        if model:
            return [executable, "--model", model, "--print", prompt]
        return [executable, "--print", prompt]
    if agent_name == "codex":
        if model:
            return [executable, "exec", "-m", model, prompt]
        return [executable, "exec", prompt]
    if agent_name == "gemini":
        if model:
            return [executable, "-m", model, prompt]
        return [executable, prompt]
    if agent_name == "aider":
        if model:
            return [executable, "--model", model, "--message", prompt, "--no-git"]
        return [executable, "--message", prompt, "--no-git"]
    return [executable, prompt]


def _invoke_cli_agent(
    agent_name: str,
    executable: str,
    prompt: str,
    model: Optional[str] = None,
    timeout_s: int = 60,
) -> dict:
    """Invoke a CLI agent and return captured stdout/stderr."""
    cmd = _build_cli_command(agent_name, executable, prompt, model)
    result = subprocess.run(
        cmd,
        capture_output=True,
        text=True,
        timeout=timeout_s,
        check=True,
        shell=False,
    )
    return {"stdout": result.stdout, "stderr": result.stderr}


def _estimate_cost(agent_name: str, tokens_est: int) -> str:
    """Return cost as a Decimal string; never float."""
    rate = COST_PER_1M_TOKENS.get(agent_name, Decimal("1.00"))
    cost = (rate * Decimal(tokens_est)) / Decimal("1000000")
    return str(cost.quantize(Decimal("0.000001")))


def _estimate_tokens(prompt: str, output: str) -> int:
    """Cheap deterministic token estimate from character count."""
    char_count = len(prompt) + len(output)
    return max(1, (char_count + 3) // 4)


def _inject_skill_pack(prompt: str, skill_pack: list[str]) -> str:
    """Prepend selected skill names to the prompt body."""
    if not skill_pack:
        return prompt
    headers = "\n".join(f"[SKILL: {skill_name}]" for skill_name in skill_pack)
    return f"{headers}\n\n{prompt}"


def _build_cli_evidence_id(output: str) -> str:
    """Build a deterministic evidence fingerprint for one generation."""
    digest = hashlib.sha256(output.encode("utf-8")).hexdigest()
    return f"sha256:{digest}"


# ---------------------------------------------------------------------------
# Evidence storage — append-only JSONL log
# ---------------------------------------------------------------------------
def _part11_storage_paths() -> tuple[Path, Path, Path]:
    if (
        PART11_EVIDENCE_DIR != DEFAULT_PART11_EVIDENCE_DIR
        or PART11_EVIDENCE_PATH != DEFAULT_PART11_EVIDENCE_PATH
        or PART11_CHAIN_LOCK_PATH != DEFAULT_PART11_CHAIN_LOCK_PATH
    ):
        return PART11_EVIDENCE_DIR, PART11_EVIDENCE_PATH, PART11_CHAIN_LOCK_PATH
    if EVIDENCE_PATH != DEFAULT_EVIDENCE_PATH:
        evidence_dir = EVIDENCE_PATH.parent / "evidence"
        return evidence_dir, evidence_dir / "evidence.jsonl", evidence_dir / "chain.lock"
    return PART11_EVIDENCE_DIR, PART11_EVIDENCE_PATH, PART11_CHAIN_LOCK_PATH


def _read_part11_chain_tip() -> str:
    _, _, chain_lock_path = _part11_storage_paths()
    try:
        lines = chain_lock_path.read_text().splitlines()
    except IOError:
        return ""
    for line in reversed(lines):
        chain_tip = line.strip().lower()
        if chain_tip:
            return chain_tip
    return ""


def _load_part11_evidence_bundles() -> list[dict]:
    _, evidence_path, _ = _part11_storage_paths()
    try:
        lines = evidence_path.read_text().splitlines()
    except IOError:
        return []
    bundles = []
    for line in lines:
        payload = line.strip()
        if not payload:
            continue
        try:
            loaded = json.loads(payload)
        except json.JSONDecodeError:
            continue
        if isinstance(loaded, dict):
            bundles.append(loaded)
    return bundles


def create_and_store_evidence_bundle(
    action_type: str,
    before_state: object,
    after_state: object,
    oauth3_token_id: str,
    user_id: str,
) -> dict:
    with _PART11_EVIDENCE_LOCK:
        evidence_dir, evidence_path, chain_lock_path = _part11_storage_paths()
        previous_bundle_sha256 = _read_part11_chain_tip() or None
        bundle = ALCOABundle.create_bundle(
            action_type,
            before_state,
            after_state,
            oauth3_token_id,
            user_id,
            previous_bundle_sha256=previous_bundle_sha256,
        )
        bundle_sha256 = ALCOABundle.bundle_sha256(bundle)
        evidence_dir.mkdir(parents=True, exist_ok=True)
        with evidence_path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(bundle, sort_keys=True) + "\n")
        with chain_lock_path.open("a", encoding="utf-8") as handle:
            handle.write(f"{bundle_sha256}\n")
    return bundle


def list_part11_evidence_bundles(
    limit: int = 50,
    since_iso8601: str = "",
    action_type: str = "",
) -> list[dict]:
    bundles = _load_part11_evidence_bundles()
    if since_iso8601:
        bundles = [bundle for bundle in bundles if str(bundle.get("timestamp_iso8601", "")) >= since_iso8601]
    if action_type:
        bundles = [bundle for bundle in bundles if bundle.get("action_type") == action_type]
    bundles.reverse()
    return bundles[:limit]


def part11_compliance_report() -> dict:
    compliant_count = 0
    partial_count = 0
    non_compliant_count = 0
    bundles = _load_part11_evidence_bundles()
    for bundle in bundles:
        status = ALCOABundle.check_compliance(bundle)
        if status == ComplianceStatus.COMPLIANT:
            compliant_count += 1
        elif status == ComplianceStatus.PARTIALLY_COMPLIANT:
            partial_count += 1
        else:
            non_compliant_count += 1
    return {
        "compliant_count": compliant_count,
        "partial_count": partial_count,
        "non_compliant": non_compliant_count,
        "total": len(bundles),
        "rung": RUNG_ACHIEVED,
    }


def verify_part11_evidence_chain() -> dict:
    bundles = _load_part11_evidence_bundles()
    validation = ALCOABundle.validate_chain(bundles)
    return {
        "chain_valid": validation.chain_valid,
        "total_bundles": len(bundles),
        "broken_at_index": validation.broken_at_index,
    }


def repair_part11_evidence_chain() -> dict[str, Any]:
    with _PART11_EVIDENCE_LOCK:
        evidence_dir, evidence_path, chain_lock_path = _part11_storage_paths()
        bundles = _load_part11_evidence_bundles()
        if not bundles:
            return {
                "success": True,
                "repaired_count": 0,
                "total_bundles": 0,
                "backup_path": None,
                "chain_valid": True,
                "broken_at_index": None,
            }

        validation = ALCOABundle.validate_chain(bundles)
        backup_path = None
        if evidence_path.exists():
            backup_path = str(evidence_dir / f"evidence.{int(time.time())}.bak.jsonl")
            shutil.copy2(evidence_path, backup_path)
        if chain_lock_path.exists() and backup_path is not None:
            shutil.copy2(chain_lock_path, evidence_dir / f"chain.{int(time.time())}.bak.lock")

        repaired_count = 0
        prior_bundle_sha256 = ""
        repaired_bundles: list[dict[str, Any]] = []
        chain_lines: list[str] = []
        for bundle in bundles:
            repaired = dict(bundle)
            alcoa_fields = repaired.get("alcoa_fields")
            if not isinstance(alcoa_fields, dict):
                alcoa_fields = {}
                repaired["alcoa_fields"] = alcoa_fields
            consistent = alcoa_fields.get("consistent")
            if not isinstance(consistent, dict):
                consistent = {}
                alcoa_fields["consistent"] = consistent
            expected_previous_sha256 = prior_bundle_sha256 or GENESIS_CHAIN_SEED
            if consistent.get("previous_bundle_sha256") != expected_previous_sha256:
                consistent["previous_bundle_sha256"] = expected_previous_sha256
                consistent["passed"] = True
            current_bundle_sha256 = ALCOABundle.bundle_sha256(repaired)
            expected_chain_link = _sha256_hex(f"{expected_previous_sha256}{current_bundle_sha256}")
            if str(repaired.get("sha256_chain_link") or "").lower() != expected_chain_link:
                repaired["sha256_chain_link"] = expected_chain_link
                repaired_count += 1
            repaired_bundles.append(repaired)
            chain_lines.append(current_bundle_sha256)
            prior_bundle_sha256 = current_bundle_sha256

        evidence_dir.mkdir(parents=True, exist_ok=True)
        with evidence_path.open("w", encoding="utf-8") as handle:
            for bundle in repaired_bundles:
                handle.write(json.dumps(bundle, sort_keys=True) + "\n")
        with chain_lock_path.open("w", encoding="utf-8") as handle:
            for line in chain_lines:
                handle.write(f"{line}\n")

        after_validation = ALCOABundle.validate_chain(repaired_bundles)
        return {
            "success": after_validation.chain_valid,
            "repaired_count": repaired_count,
            "total_bundles": len(repaired_bundles),
            "backup_path": backup_path,
            "chain_valid": after_validation.chain_valid,
            "broken_at_index": after_validation.broken_at_index,
            "broken_at_index_before": validation.broken_at_index,
        }


def _append_evidence_record(event_type: str, data: dict[str, Any]) -> dict[str, Any]:
    record = {
        "id": str(uuid.uuid4()),
        "type": event_type,
        "ts": int(time.time()),
        "data": data,
    }
    EVIDENCE_PATH.parent.mkdir(parents=True, exist_ok=True)
    with EVIDENCE_PATH.open("a", encoding="utf-8") as fh:
        fh.write(json.dumps(record) + "\n")
    return record


def record_evidence(event_type: str, data: dict) -> dict:
    """Append one evidence event to ~/.solace/evidence.jsonl. Returns the record."""
    record = _append_evidence_record(event_type, data)
    create_and_store_evidence_bundle(
        action_type=event_type,
        before_state=data.get("before_state_hash", {}),
        after_state=data.get("after_state_hash", data),
        oauth3_token_id=str(data.get("oauth3_token_id") or "system"),
        user_id=str(data.get("user_id") or "system"),
    )
    return record


class OAuth3VaultError(Exception):
    """Base OAuth3 vault error."""


class OAuth3TokenNotFoundError(OAuth3VaultError):
    """Raised when a token id is not present in the OAuth3 vault."""


class OAuth3VaultUserMismatchError(OAuth3VaultError):
    """Raised when a persisted vault belongs to a different local user hash."""


class OAuth3VaultCorruptError(OAuth3VaultError):
    """Raised when the encrypted OAuth3 vault cannot be parsed or decrypted."""


class PZipCompressionError(Exception):
    """Prime Wiki content compression failed."""


class PZipRTCError(PZipCompressionError):
    """Prime Wiki round-trip verification failed."""


def _oauth3_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _oauth3_parse_iso8601(raw: str) -> datetime:
    normalized = raw[:-1] + "+00:00" if raw.endswith("Z") else raw
    parsed = datetime.fromisoformat(normalized)
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _oauth3_hash_user_id(user_id: str) -> str:
    return hashlib.sha256(user_id.encode("utf-8")).hexdigest()


def _oauth3_default_state(user_id_hash: str = "") -> dict[str, Any]:
    return {
        "schema_version": "1.0",
        "user_id_hash": user_id_hash,
        "tokens": {},
        "evidence": [],
        "chain_tip": OAUTH3_EVIDENCE_GENESIS_HASH,
    }


def _oauth3_normalize_state(raw_state: Any, user_id_hash: str = "") -> dict[str, Any]:
    if not isinstance(raw_state, dict):
        raise OAuth3VaultCorruptError("vault state must be a JSON object")
    tokens = raw_state.get("tokens", {})
    evidence = raw_state.get("evidence", [])
    if not isinstance(tokens, dict):
        raise OAuth3VaultCorruptError("vault tokens must be a JSON object")
    if not isinstance(evidence, list):
        raise OAuth3VaultCorruptError("vault evidence must be a JSON array")
    chain_tip = raw_state.get("chain_tip", OAUTH3_EVIDENCE_GENESIS_HASH)
    if not isinstance(chain_tip, str) or not chain_tip:
        chain_tip = OAUTH3_EVIDENCE_GENESIS_HASH
    stored_user_id_hash = raw_state.get("user_id_hash", user_id_hash)
    if not isinstance(stored_user_id_hash, str):
        stored_user_id_hash = user_id_hash
    return {
        "schema_version": str(raw_state.get("schema_version", "1.0")),
        "user_id_hash": stored_user_id_hash,
        "tokens": tokens,
        "evidence": evidence,
        "chain_tip": chain_tip,
    }


def _oauth3_derive_key(session_token_sha256: str, user_id_hash: str) -> bytes:
    if not _SHA256_HEX_RE.fullmatch(user_id_hash):
        raise OAuth3VaultCorruptError("vault KDF salt must be a 64-char sha256 hex string")
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=bytes.fromhex(user_id_hash),
        iterations=OAUTH3_PBKDF2_ITERATIONS,
    )
    return kdf.derive(session_token_sha256.encode("utf-8"))


def _oauth3_encrypt_state(state: dict[str, Any], session_token_sha256: str) -> str:
    user_id_hash = state.get("user_id_hash", "")
    if not isinstance(user_id_hash, str) or not _SHA256_HEX_RE.fullmatch(user_id_hash):
        raise OAuth3VaultCorruptError("vault user_id_hash missing or invalid")
    plaintext = json.dumps(state, sort_keys=True, separators=(",", ":")).encode("utf-8")
    nonce = secrets.token_bytes(12)
    ciphertext = AESGCM(_oauth3_derive_key(session_token_sha256, user_id_hash)).encrypt(nonce, plaintext, None)
    envelope = {
        "cipher": "AES-256-GCM",
        "nonce_b64": base64.b64encode(nonce).decode("ascii"),
        "ciphertext_b64": base64.b64encode(ciphertext).decode("ascii"),
        "ciphertext_sha256": hashlib.sha256(ciphertext).hexdigest(),
        "kdf": {
            "algorithm": "PBKDF2-HMAC-SHA256",
            "iterations": OAUTH3_PBKDF2_ITERATIONS,
            "salt_hex": user_id_hash,
        },
    }
    return json.dumps(envelope, sort_keys=True, separators=(",", ":"))


def _oauth3_load_vault_state(session_token_sha256: str, user_id_hash_hint: str = "") -> dict[str, Any]:
    if not OAUTH3_VAULT_PATH.exists():
        return _oauth3_default_state(user_id_hash_hint)
    try:
        envelope = json.loads(OAUTH3_VAULT_PATH.read_text())
    except FileNotFoundError:
        return _oauth3_default_state(user_id_hash_hint)
    except json.JSONDecodeError as exc:
        raise OAuth3VaultCorruptError(f"vault JSON decode failed: {exc}") from exc
    except OSError as exc:
        raise OAuth3VaultCorruptError(f"vault read failed: {exc}") from exc
    if not isinstance(envelope, dict):
        raise OAuth3VaultCorruptError("vault envelope must be a JSON object")
    kdf = envelope.get("kdf", {})
    if not isinstance(kdf, dict):
        raise OAuth3VaultCorruptError("vault envelope missing kdf metadata")
    salt_hex = kdf.get("salt_hex", "")
    nonce_b64 = envelope.get("nonce_b64", "")
    ciphertext_b64 = envelope.get("ciphertext_b64", "")
    ciphertext_sha256 = envelope.get("ciphertext_sha256", "")
    if not isinstance(salt_hex, str) or not isinstance(nonce_b64, str) or not isinstance(ciphertext_b64, str):
        raise OAuth3VaultCorruptError("vault envelope fields must be strings")
    try:
        nonce = base64.b64decode(nonce_b64)
        ciphertext = base64.b64decode(ciphertext_b64)
        plaintext = AESGCM(_oauth3_derive_key(session_token_sha256, salt_hex)).decrypt(nonce, ciphertext, None)
        decoded = json.loads(plaintext.decode("utf-8"))
    except (binascii.Error, InvalidTag, KeyError, OSError, TypeError, UnicodeDecodeError, ValueError, json.JSONDecodeError) as exc:
        raise OAuth3VaultCorruptError(f"vault decrypt failed: {exc}") from exc
    if isinstance(ciphertext_sha256, str) and ciphertext_sha256:
        actual_ciphertext_sha256 = hashlib.sha256(ciphertext).hexdigest()
        if actual_ciphertext_sha256 != ciphertext_sha256:
            raise OAuth3VaultCorruptError("vault ciphertext sha256 mismatch")
    state = _oauth3_normalize_state(decoded, salt_hex)
    if user_id_hash_hint and state.get("user_id_hash") and state["user_id_hash"] != user_id_hash_hint:
        raise OAuth3VaultUserMismatchError("oauth3 vault already initialized for a different local user")
    if not state.get("user_id_hash"):
        state["user_id_hash"] = salt_hex or user_id_hash_hint
    return state


def _oauth3_save_vault_state(state: dict[str, Any], session_token_sha256: str) -> None:
    normalized = _oauth3_normalize_state(state, str(state.get("user_id_hash", "")))
    if not normalized["user_id_hash"]:
        raise OAuth3VaultCorruptError("cannot persist vault without user_id_hash")
    OAUTH3_VAULT_PATH.parent.mkdir(parents=True, exist_ok=True)
    OAUTH3_VAULT_PATH.write_text(_oauth3_encrypt_state(normalized, session_token_sha256))


def _oauth3_is_high_risk_scope(scope: str) -> bool:
    normalized = scope.strip().lower()
    if not normalized or normalized.startswith("post.draft"):
        return False
    segments = [segment for segment in re.split(r"[^a-z]+", normalized) if segment]
    return any(segment in OAUTH3_HIGH_RISK_ACTIONS for segment in segments)


def _oauth3_step_up_scopes(scopes: list[str]) -> list[str]:
    required: list[str] = []
    for scope in scopes:
        if _oauth3_is_high_risk_scope(scope) and scope not in required:
            required.append(scope)
    return required


def _oauth3_validate_scopes(raw_scopes: Any) -> list[str]:
    if not isinstance(raw_scopes, list) or not raw_scopes:
        raise ValueError("scopes must be a non-empty list")
    cleaned: list[str] = []
    for raw_scope in raw_scopes:
        if not isinstance(raw_scope, str):
            raise ValueError("each scope must be a string")
        scope = raw_scope.strip()
        if not scope:
            raise ValueError("scope values must not be empty")
        if len(scope) > 128:
            raise ValueError("scope values must be 128 chars or fewer")
        if scope not in cleaned:
            cleaned.append(scope)
    return cleaned


def _oauth3_validate_ttl_seconds(raw_ttl: Any) -> int:
    if not isinstance(raw_ttl, int):
        raise ValueError("ttl_seconds must be an integer")
    if raw_ttl <= 0:
        raise ValueError("ttl_seconds must be positive")
    if raw_ttl > OAUTH3_MAX_TTL_SECONDS:
        raise ValueError(f"ttl_seconds must be <= {OAUTH3_MAX_TTL_SECONDS}")
    return raw_ttl


def _oauth3_token_valid(token: dict[str, Any], now: Optional[datetime] = None) -> tuple[bool, str]:
    if bool(token.get("revoked", False)):
        return False, "revoked"
    expires_at = token.get("expires_at", "")
    if not isinstance(expires_at, str) or not expires_at:
        return False, "missing_expiry"
    current_time = now or datetime.now(timezone.utc)
    if current_time >= _oauth3_parse_iso8601(expires_at):
        return False, "expired"
    return True, "ok"


def _oauth3_token_view(token: dict[str, Any]) -> dict[str, Any]:
    token_id = str(token.get("token_id", ""))
    return {
        "token_id": token_id,
        "id": token_id,
        "scopes": list(token.get("scopes", [])),
        "expires_at": token.get("expires_at"),
        "issued_at": token.get("issued_at"),
        "revoked": bool(token.get("revoked", False)),
        "revoked_at": token.get("revoked_at"),
        "step_up_required": list(token.get("step_up_required", [])),
    }


def _oauth3_append_evidence(
    state: dict[str, Any],
    event_type: str,
    *,
    token: Optional[dict[str, Any]] = None,
    data: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    payload = data.copy() if isinstance(data, dict) else {}
    token_id = str(token.get("token_id", "")) if token is not None else str(payload.pop("token_id", ""))
    scopes = list(token.get("scopes", [])) if token is not None else list(payload.pop("scopes", []))
    previous_hash = str(state.get("chain_tip") or OAUTH3_EVIDENCE_GENESIS_HASH)
    event = {
        "event_type": event_type,
        "token_id": token_id,
        "scopes": scopes,
        "timestamp": _oauth3_now_iso(),
        "previous_hash": previous_hash,
        "data": payload,
    }
    event_sha256 = hashlib.sha256(
        json.dumps(event, sort_keys=True, separators=(",", ":")).encode("utf-8")
    ).hexdigest()
    chain_link_sha256 = hashlib.sha256(f"{previous_hash}{event_sha256}".encode("utf-8")).hexdigest()
    event["chain_link_sha256"] = chain_link_sha256
    state.setdefault("evidence", []).append(event)
    state["chain_tip"] = chain_link_sha256
    if token is not None:
        token["evidence_chain_tip"] = chain_link_sha256
    return event


def _oauth3_filter_evidence(state: dict[str, Any], limit: int = 50, since: str = "") -> list[dict[str, Any]]:
    evidence = state.get("evidence", [])
    if not isinstance(evidence, list):
        return []
    filtered: list[dict[str, Any]] = []
    since_dt: Optional[datetime] = None
    if since:
        since_dt = _oauth3_parse_iso8601(since)
    for row in evidence:
        if not isinstance(row, dict):
            continue
        if since_dt is not None:
            timestamp = row.get("timestamp", "")
            if not isinstance(timestamp, str):
                continue
            if _oauth3_parse_iso8601(timestamp) < since_dt:
                continue
        filtered.append({
            "event_type": row.get("event_type", ""),
            "token_id": row.get("token_id", ""),
            "scopes": row.get("scopes", []),
            "timestamp": row.get("timestamp", ""),
            "chain_link_sha256": row.get("chain_link_sha256", ""),
        })
    return filtered[-limit:]


def _oauth3_legacy_token_view(token: dict[str, Any]) -> dict[str, Any]:
    safe = {key: value for key, value in token.items() if key != "token_sha256"}
    token_id = str(safe.get("token_id") or safe.get("id") or "")
    if token_id:
        safe["token_id"] = token_id
        safe["id"] = token_id
    return safe


def _oauth3_active_token_rows(session_token_sha256: str) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    seen_token_ids: set[str] = set()
    if OAUTH3_VAULT_PATH.exists():
        state = _oauth3_load_vault_state(session_token_sha256)
        for token in state.get("tokens", {}).values():
            if not isinstance(token, dict):
                continue
            token_id = str(token.get("token_id", ""))
            if not token_id:
                continue
            valid, _ = _oauth3_token_valid(token)
            if not valid:
                continue
            rows.append(_oauth3_token_view(token))
            seen_token_ids.add(token_id)
    for token in load_oauth3_tokens():
        if not isinstance(token, dict):
            continue
        token_id = str(token.get("token_id") or token.get("id") or "")
        if not token_id or token_id in seen_token_ids:
            continue
        if bool(token.get("revoked", False)):
            continue
        rows.append(_oauth3_legacy_token_view(token))
    return rows


def _load_cloud_api_key() -> str:
    try:
        settings = json.loads(SETTINGS_PATH.read_text())
    except FileNotFoundError:
        return ""
    except json.JSONDecodeError:
        return ""
    except OSError:
        return ""
    if not isinstance(settings, dict):
        return ""
    account = settings.get("account", {})
    if not isinstance(account, dict):
        return ""
    api_key = account.get("api_key", "")
    return api_key if isinstance(api_key, str) else ""


def _load_account_tier() -> str:
    onboarding = _load_onboarding_state()
    auth_state = str(onboarding.get("auth_state", "logged_out"))
    membership_tier = _normalize_membership_tier(onboarding.get("membership_tier", "free"))
    if auth_state == "logged_in":
        return membership_tier
    try:
        settings = json.loads(SETTINGS_PATH.read_text())
    except FileNotFoundError:
        return "free"
    except json.JSONDecodeError:
        return "free"
    except OSError:
        return "free"
    if not isinstance(settings, dict):
        return "free"
    user = settings.get("user", {})
    if isinstance(user, dict):
        tier = user.get("tier")
        if isinstance(tier, str):
            normalized = tier.strip().lower()
            if normalized in _MARKETPLACE_TIER_RANKS:
                return normalized
    account = settings.get("account", {})
    if not isinstance(account, dict):
        return "free"
    tier = account.get("tier", "free")
    if not isinstance(tier, str):
        return "free"
    normalized = tier.strip().lower()
    if normalized not in _MARKETPLACE_TIER_RANKS:
        return "free"
    return normalized


def _load_user_tier_payload() -> dict:
    onboarding = _load_onboarding_state()
    tier = _normalize_membership_tier(onboarding.get("membership_tier", _load_account_tier()))
    tier_rank = _MARKETPLACE_TIER_RANKS.get(tier, 0)
    pro_rank = _MARKETPLACE_TIER_RANKS["pro"]
    return {
        "tier": tier,
        "auth_state": onboarding.get("auth_state", "logged_out"),
        "apps_enabled": bool(onboarding.get("apps_enabled", False)),
        "model_source": onboarding.get("model_source"),
        "managed_llm_enabled": bool(onboarding.get("managed_llm_enabled", False)),
        "device_id": onboarding.get("device_id", _default_device_id()),
        "can_sync": tier_rank >= pro_rank,
        "can_submit": tier_rank >= pro_rank,
        "can_remote_control": tier_rank >= pro_rank,
    }


def _sync_heartbeat_payload(repo_root: str, session_token_sha256: str, tracked_sessions: dict[str, Any]) -> dict[str, Any]:
    _ensure_default_domain_profiles(repo_root)
    onboarding = _load_onboarding_state()
    profiles = _load_domain_profiles()
    domain_events = _load_domain_events()
    model_sources = list(_normalize_model_sources(onboarding.get("model_sources", [])))
    managed_llm_enabled = bool(onboarding.get("managed_llm_enabled", False))
    if managed_llm_enabled and "managed" not in model_sources:
        model_sources.append("managed")
    settings = _load_settings()
    account = settings.get("account", {}) if isinstance(settings, dict) else {}
    if not isinstance(account, dict):
        account = {}
    domain_count = len(profiles)
    active_domain_count = sum(1 for profile in profiles.values() if isinstance(profile, dict) and bool(profile.get("active")))
    oauth3_token_count = len(_oauth3_active_token_rows(session_token_sha256))
    event_count = len(domain_events)
    recent_domains: list[str] = []
    for event in sorted(domain_events, key=lambda row: int(row.get("ts", 0)), reverse=True):
        normalized = _normalize_domain(event.get("domain"))
        if not normalized or normalized in recent_domains:
            continue
        recent_domains.append(normalized)
        if len(recent_domains) >= 8:
            break
    return {
        "device_id": str(onboarding.get("device_id") or _default_device_id()),
        "client_version": _SERVER_VERSION,
        "apps_enabled": bool(onboarding.get("apps_enabled", False)),
        "membership_plan": _normalize_membership_tier(onboarding.get("membership_tier", "free")),
        "membership_status": str(account.get("membership_status") or account.get("status") or "active").strip().lower() or "active",
        "managed_llm_enabled": managed_llm_enabled,
        "model_source": onboarding.get("model_source"),
        "model_sources": model_sources,
        "queue_depth": len(tracked_sessions) if isinstance(tracked_sessions, dict) else 0,
        "domain_count": domain_count,
        "active_domain_count": active_domain_count,
        "oauth3_token_count": oauth3_token_count,
        "event_count": event_count,
        "recent_domains": recent_domains,
    }


def _push_heartbeat_to_cloud(
    *,
    api_key: str,
    repo_root: str,
    session_token_sha256: str,
    tracked_sessions: dict[str, Any],
) -> tuple[dict[str, Any], Optional[dict[str, Any]], Optional[str]]:
    payload = _sync_heartbeat_payload(repo_root, session_token_sha256, tracked_sessions)
    request = urllib.request.Request(
        SYNC_HEARTBEAT_URL,
        data=json.dumps(payload).encode(),
        headers={
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        },
        method="POST",
    )
    try:
        with _sync_urlopen(request, timeout=10) as response:
            response_body = response.read().decode()
    except urllib.error.HTTPError as exc:
        message = exc.read().decode(errors="replace") if exc.fp is not None else ""
        return payload, None, f"heartbeat sync rejected ({exc.code}): {message}"
    except urllib.error.URLError:
        return payload, None, "heartbeat sync unavailable"
    try:
        remote = json.loads(response_body) if response_body else {}
    except json.JSONDecodeError:
        remote = {}
    record_evidence("heartbeat_synced", {"device_id": payload["device_id"], "domain_count": payload["domain_count"]})
    return payload, remote, None


def _fun_pack_sha256(pack: dict[str, Any]) -> str:
    normalized = json.loads(json.dumps(pack))
    meta = normalized.get("_meta", {})
    if not isinstance(meta, dict):
        meta = {}
    meta["sha256"] = "COMPUTED_AT_LOAD"
    normalized["_meta"] = meta
    sealed = json.dumps(normalized, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return hashlib.sha256(sealed).hexdigest()


def _load_fun_pack(pack_id: str) -> dict[str, Any]:
    """Load one fun pack JSON object and compute its sealed sha256 metadata."""
    pack_path = FUN_PACKS_DIR / f"{pack_id}.json"
    if not pack_path.exists():
        raise FileNotFoundError(f"Fun pack '{pack_id}' not found")
    data = json.loads(pack_path.read_text(encoding="utf-8"))
    if not isinstance(data, dict):
        raise json.JSONDecodeError("fun pack must be an object", pack_path.name, 0)
    meta = data.get("_meta", {})
    if not isinstance(meta, dict):
        meta = {}
    meta["sha256"] = _fun_pack_sha256(data)
    data["_meta"] = meta
    return data


def _get_active_pack_id() -> str:
    """Get configured active fun pack id, defaulting to the bundled English pack."""
    try:
        payload = json.loads(ACTIVE_PACK_PATH.read_text(encoding="utf-8"))
    except FileNotFoundError:
        return DEFAULT_FUN_PACK_ID
    except json.JSONDecodeError:
        return DEFAULT_FUN_PACK_ID
    except OSError:
        return DEFAULT_FUN_PACK_ID
    if not isinstance(payload, dict):
        return DEFAULT_FUN_PACK_ID
    active_pack_id = payload.get("active_pack_id", DEFAULT_FUN_PACK_ID)
    return active_pack_id if isinstance(active_pack_id, str) and active_pack_id else DEFAULT_FUN_PACK_ID


def _resolve_active_pack_id() -> str:
    configured_pack_id = _get_active_pack_id()
    try:
        _load_fun_pack(configured_pack_id)
        return configured_pack_id
    except FileNotFoundError:
        return DEFAULT_FUN_PACK_ID
    except json.JSONDecodeError:
        return DEFAULT_FUN_PACK_ID
    except OSError:
        return DEFAULT_FUN_PACK_ID


def _load_active_fun_pack() -> dict[str, Any]:
    return _load_fun_pack(_resolve_active_pack_id())


def _set_active_pack_id(pack_id: str) -> None:
    ACTIVE_PACK_PATH.parent.mkdir(parents=True, exist_ok=True)
    ACTIVE_PACK_PATH.write_text(json.dumps({"active_pack_id": pack_id}), encoding="utf-8")


def _list_available_packs() -> list[dict[str, Any]]:
    if not FUN_PACKS_DIR.exists():
        return []
    active_pack_id = _resolve_active_pack_id()
    packs: list[dict[str, Any]] = []
    for pack_path in sorted(FUN_PACKS_DIR.glob("*.json")):
        try:
            pack = _load_fun_pack(pack_path.stem)
        except FileNotFoundError:
            continue
        except json.JSONDecodeError:
            continue
        except OSError:
            continue
        meta = pack.get("_meta", {})
        if not isinstance(meta, dict):
            meta = {}
        pack_id = str(meta.get("id") or pack_path.stem)
        packs.append(
            {
                "id": pack_id,
                "name": str(meta.get("name") or pack_path.stem),
                "locale": str(meta.get("locale") or "en"),
                "version": str(meta.get("version") or "1.0.0"),
                "active": pack_id == active_pack_id,
                "jokes_count": len(pack.get("jokes", [])),
                "facts_count": len(pack.get("facts", [])),
                "greetings_count": len(pack.get("greetings", [])),
                "seasonal_count": len(pack.get("seasonal", [])),
            }
        )
    return packs


_prime_wiki_urlopen = urllib.request.urlopen


def _prime_wiki_timestamp() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="microseconds").replace("+00:00", "Z")


def _normalize_prime_wiki_url(url: str) -> str:
    parsed = urllib.parse.urlsplit(url.strip())
    if not parsed.scheme or not parsed.netloc:
        return ""
    normalized_path = parsed.path.rstrip("/") or "/"
    return urllib.parse.urlunsplit(
        (parsed.scheme.lower(), parsed.netloc.lower(), normalized_path, "", "")
    )


def _prime_wiki_url_hash(normalized_url: str) -> str:
    return hashlib.sha256(normalized_url.encode("utf-8")).hexdigest()


def _prime_wiki_storage_dir(url_hash: str) -> Path:
    return PRIME_WIKI_ROOT / url_hash


def _prime_wiki_clean_text(value: str) -> str:
    without_tags = re.sub(r"<[^>]+>", " ", value)
    return re.sub(r"\s+", " ", without_tags).strip()


def _prime_wiki_unique_text(values: list[str]) -> list[str]:
    unique_values: list[str] = []
    seen: set[str] = set()
    for value in values:
        normalized = re.sub(r"\s+", " ", value).strip()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        unique_values.append(normalized)
    return unique_values


def _prime_wiki_meta_content(tag: object) -> str:
    if BeautifulSoup is None:
        return ""
    if tag is None:
        return ""
    content = tag.get("content", "")
    return content.strip() if isinstance(content, str) else ""


def _prime_wiki_rel_contains_canonical(value: object) -> bool:
    if isinstance(value, list):
        return "canonical" in [str(item).strip().lower() for item in value]
    if isinstance(value, str):
        return "canonical" in value.strip().lower().split()
    return False


def extract_metadata(html: str) -> dict:
    if BeautifulSoup is not None:
        soup = BeautifulSoup(html, "html.parser")
        og_title = ""
        og_description = ""
        canonical_url = ""

        og_title_tag = soup.find("meta", attrs={"property": "og:title"})
        if og_title_tag is None:
            og_title_tag = soup.find("meta", attrs={"name": "og:title"})
        og_title = _prime_wiki_meta_content(og_title_tag)

        og_description_tag = soup.find("meta", attrs={"property": "og:description"})
        if og_description_tag is None:
            og_description_tag = soup.find("meta", attrs={"name": "og:description"})
        og_description = _prime_wiki_meta_content(og_description_tag)
        if not og_description:
            description_tag = soup.find("meta", attrs={"name": "description"})
            og_description = _prime_wiki_meta_content(description_tag)

        for link in soup.find_all("link"):
            rel_value = link.get("rel")
            if _prime_wiki_rel_contains_canonical(rel_value):
                href = link.get("href", "")
                if isinstance(href, str):
                    canonical_url = href.strip()
                    if canonical_url:
                        break

        return {
            "og_title": og_title,
            "og_description": og_description,
            "canonical_url": canonical_url,
        }

    og_title_match = re.search(
        r'<meta[^>]+(?:property|name)=["\']og:title["\'][^>]+content=["\']([^"\']+)["\']',
        html,
        re.I,
    )
    og_description_match = re.search(
        r'<meta[^>]+(?:property|name)=["\']og:description["\'][^>]+content=["\']([^"\']+)["\']',
        html,
        re.I,
    )
    if og_description_match is None:
        og_description_match = re.search(
            r'<meta[^>]+name=["\']description["\'][^>]+content=["\']([^"\']+)["\']',
            html,
            re.I,
        )
    canonical_match = re.search(
        r'href=["\']([^"\']+)["\'][^>]*rel=["\']canonical["\']|'
        r'rel=["\']canonical["\'][^>]*href=["\']([^"\']+)["\']',
        html,
        re.I,
    )
    return {
        "og_title": og_title_match.group(1).strip() if og_title_match else "",
        "og_description": og_description_match.group(1).strip() if og_description_match else "",
        "canonical_url": (canonical_match.group(1) or canonical_match.group(2)).strip()
        if canonical_match
        else "",
    }


def _extract_title(html: str) -> str:
    if BeautifulSoup is not None:
        soup = BeautifulSoup(html, "html.parser")
        if soup.title is not None:
            title_text = soup.title.get_text(" ", strip=True)
            if title_text:
                return title_text
        metadata = extract_metadata(html)
        og_title = metadata.get("og_title", "")
        return og_title if isinstance(og_title, str) else ""

    title_match = re.search(r"<title[^>]*>(.*?)</title>", html, re.I | re.S)
    if title_match:
        return _prime_wiki_clean_text(title_match.group(1))
    metadata = extract_metadata(html)
    og_title = metadata.get("og_title", "")
    return og_title if isinstance(og_title, str) else ""


def extract_headings(html: str) -> list[str]:
    if BeautifulSoup is not None:
        soup = BeautifulSoup(html, "html.parser")
        headings = [tag.get_text(" ", strip=True) for tag in soup.find_all(["h1", "h2", "h3"])]
        return _prime_wiki_unique_text(headings)

    matches = re.findall(r"<h[1-3][^>]*>(.*?)</h[1-3]>", html, re.I | re.S)
    return _prime_wiki_unique_text([_prime_wiki_clean_text(match) for match in matches])


def _prime_wiki_is_action_cta(text: str, href: str = "") -> bool:
    haystack = f"{text} {href}".lower()
    for verb in PRIME_WIKI_CTA_VERBS:
        if re.search(rf"\b{re.escape(verb)}\b", haystack):
            return True
    return False


def extract_ctas(html: str) -> list[str]:
    ctas: list[str] = []
    if BeautifulSoup is not None:
        soup = BeautifulSoup(html, "html.parser")
        for button in soup.find_all("button"):
            text = button.get_text(" ", strip=True)
            if text:
                ctas.append(text)
        for input_tag in soup.find_all("input"):
            input_type = str(input_tag.get("type", "")).strip().lower()
            if input_type in ("submit", "button"):
                value = str(input_tag.get("value", "")).strip()
                if value:
                    ctas.append(value)
        for link in soup.find_all("a"):
            text = link.get_text(" ", strip=True)
            href = str(link.get("href", "")).strip()
            if text and _prime_wiki_is_action_cta(text, href):
                ctas.append(text)
        return _prime_wiki_unique_text(ctas)

    button_matches = re.findall(r"<button[^>]*>(.*?)</button>", html, re.I | re.S)
    for match in button_matches:
        text = _prime_wiki_clean_text(match)
        if text:
            ctas.append(text)
    input_matches = re.findall(
        r'<input[^>]*type=["\'](?:submit|button)["\'][^>]*value=["\']([^"\']+)["\'][^>]*>',
        html,
        re.I,
    )
    for value in input_matches:
        cleaned = re.sub(r"\s+", " ", value).strip()
        if cleaned:
            ctas.append(cleaned)
    link_matches = re.findall(r'<a[^>]*href=["\']([^"\']+)["\'][^>]*>(.*?)</a>', html, re.I | re.S)
    for href, text in link_matches:
        cleaned = _prime_wiki_clean_text(text)
        if cleaned and _prime_wiki_is_action_cta(cleaned, href):
            ctas.append(cleaned)
    return _prime_wiki_unique_text(ctas)


def extract_key_elements(html: str) -> dict:
    return {
        "title": _extract_title(html),
        "headings": extract_headings(html),
        "ctas": extract_ctas(html),
        "metadata": extract_metadata(html),
    }


def _prime_wiki_pzip_binary_and_codec(raw_bytes: bytes) -> tuple[Path, str]:
    if raw_bytes:
        return PRIME_WIKI_PZIP_WEB_BINARY, PRIME_WIKI_PZIP_WEB_CODEC
    return PRIME_WIKI_PZIP_EMPTY_BINARY, PRIME_WIKI_PZIP_EMPTY_CODEC


def _run_prime_wiki_pzip(binary_path: Path, mode: str, payload: bytes) -> bytes:
    try:
        result = subprocess.run(
            [str(binary_path), mode, "-"],
            input=payload,
            capture_output=True,
            check=False,
            timeout=PRIME_WIKI_PZIP_TIMEOUT_SECONDS,
        )
    except OSError as exc:
        raise PZipCompressionError(f"pzweb unavailable: {exc}") from exc
    except subprocess.TimeoutExpired as exc:
        raise PZipCompressionError("pzweb timed out") from exc
    if result.returncode != 0:
        stderr = result.stderr.decode("utf-8", errors="replace").strip()
        raise PZipCompressionError(stderr or f"pzweb {mode} failed")
    return result.stdout


def _compress_prime_wiki_content(content: str) -> tuple[str, str, int, int, float, str, bool]:
    raw_bytes = content.encode("utf-8")
    binary_path, codec = _prime_wiki_pzip_binary_and_codec(raw_bytes)
    compressed_bytes = _run_prime_wiki_pzip(binary_path, "compress", raw_bytes)
    restored_bytes = _run_prime_wiki_pzip(binary_path, "decompress", compressed_bytes)
    if restored_bytes != raw_bytes:
        raise PZipRTCError("prime wiki snapshot failed round-trip verification")
    compressed_b64 = base64.b64encode(compressed_bytes).decode("ascii")
    sha256_value = hashlib.sha256(raw_bytes).hexdigest()
    compression_ratio = round(len(raw_bytes) / max(len(compressed_bytes), 1), 3)
    return (
        compressed_b64,
        sha256_value,
        len(raw_bytes),
        len(compressed_bytes),
        compression_ratio,
        codec,
        True,
    )


def _prime_wiki_snapshot_filename(snapshot_type: str, captured_at: str, snapshot_id: str) -> str:
    filename = f"{snapshot_type}_{captured_at}.json"
    if len(filename) <= 255:
        return filename
    return f"{snapshot_type}_{captured_at}_{snapshot_id}.json"


def _prime_wiki_public_record(record: dict) -> dict:
    public_record = dict(record)
    public_record.pop("content_gzip_b64", None)
    public_record.pop("content_pzip_b64", None)
    public_record.pop("storage_path", None)
    return public_record


def _prime_wiki_snapshot_record(
    url: str,
    content_html: str,
    snapshot_type: str,
    app_id: str,
    action_id: str,
) -> dict:
    normalized_url = _normalize_prime_wiki_url(url)
    captured_at = _prime_wiki_timestamp()
    snapshot_id = str(uuid.uuid4())
    (
        compressed_b64,
        sha256_value,
        size_bytes,
        compressed_size_bytes,
        compression_ratio,
        codec,
        rtc_verified,
    ) = _compress_prime_wiki_content(content_html)
    return {
        "snapshot_id": snapshot_id,
        "url_hash": _prime_wiki_url_hash(normalized_url),
        "url": normalized_url,
        "domain": urllib.parse.urlsplit(normalized_url).netloc.lower(),
        "snapshot_type": snapshot_type,
        "content_pzip_b64": compressed_b64,
        "key_elements": extract_key_elements(content_html),
        "compression_ratio": compression_ratio,
        "codec": codec,
        "rtc_verified": rtc_verified,
        "captured_at": captured_at,
        "captured_at_ts": time.time(),
        "app_id": app_id,
        "action_id": action_id,
        "sha256": sha256_value,
        "size_bytes": size_bytes,
        "compressed_size_bytes": compressed_size_bytes,
    }


def _store_prime_wiki_snapshot(record: dict) -> Path:
    storage_dir = _prime_wiki_storage_dir(str(record.get("url_hash", "")))
    storage_dir.mkdir(parents=True, exist_ok=True)
    snapshot_id = str(record.get("snapshot_id", ""))
    captured_at = str(record.get("captured_at", ""))
    snapshot_type = str(record.get("snapshot_type", "periodic"))
    file_path = storage_dir / _prime_wiki_snapshot_filename(snapshot_type, captured_at, snapshot_id)
    if file_path.exists():
        file_path = storage_dir / f"{snapshot_type}_{captured_at}_{snapshot_id}.json"
    record["storage_path"] = str(file_path)
    with _PRIME_WIKI_LOCK:
        file_path.write_text(json.dumps(record, indent=2))
    return file_path


def _iter_prime_wiki_snapshot_paths() -> list[Path]:
    if not PRIME_WIKI_ROOT.is_dir():
        return []
    return sorted(PRIME_WIKI_ROOT.glob("*/*.json"))


def _load_prime_wiki_snapshot_from_path(path: Path) -> Optional[dict]:
    try:
        record = json.loads(path.read_text())
    except FileNotFoundError:
        return None
    except json.JSONDecodeError:
        return None
    except OSError:
        return None
    if not isinstance(record, dict):
        return None
    record["storage_path"] = str(path)
    return record


def _find_prime_wiki_snapshot(snapshot_id: str) -> Optional[dict]:
    for path in _iter_prime_wiki_snapshot_paths():
        record = _load_prime_wiki_snapshot_from_path(path)
        if record is None:
            continue
        if record.get("snapshot_id") == snapshot_id:
            return record
    return None


def _load_all_prime_wiki_snapshots() -> list[dict]:
    records: list[dict] = []
    for path in _iter_prime_wiki_snapshot_paths():
        record = _load_prime_wiki_snapshot_from_path(path)
        if record is not None:
            records.append(record)
    return records


def _prime_wiki_diff_elements(record: dict) -> set[str]:
    key_elements = record.get("key_elements", {})
    if not isinstance(key_elements, dict):
        return set()
    elements: set[str] = set()
    title = key_elements.get("title", "")
    if isinstance(title, str) and title:
        elements.add(f"title:{title}")
    headings = key_elements.get("headings", [])
    if isinstance(headings, list):
        for heading in headings:
            if isinstance(heading, str) and heading:
                elements.add(f"heading:{heading}")
    ctas = key_elements.get("ctas", [])
    if isinstance(ctas, list):
        for cta in ctas:
            if isinstance(cta, str) and cta:
                elements.add(f"cta:{cta}")
    metadata = key_elements.get("metadata", {})
    if isinstance(metadata, dict):
        for key, value in metadata.items():
            if isinstance(value, str) and value:
                elements.add(f"metadata:{key}={value}")
    return elements


def _prime_wiki_diff_payload(before_record: dict, after_record: dict) -> dict:
    before_elements = _prime_wiki_diff_elements(before_record)
    after_elements = _prime_wiki_diff_elements(after_record)
    before_headings = before_record.get("key_elements", {}).get("headings", [])
    after_headings = after_record.get("key_elements", {}).get("headings", [])
    if not isinstance(before_headings, list):
        before_headings = []
    if not isinstance(after_headings, list):
        after_headings = []
    added_elements = sorted(after_elements - before_elements)
    removed_elements = sorted(before_elements - after_elements)
    added_headings = sorted({heading for heading in after_headings if isinstance(heading, str)} - {heading for heading in before_headings if isinstance(heading, str)})
    removed_headings = sorted({heading for heading in before_headings if isinstance(heading, str)} - {heading for heading in after_headings if isinstance(heading, str)})
    return {
        "added_elements": added_elements,
        "removed_elements": removed_elements,
        "changed_headings": {
            "added": added_headings,
            "removed": removed_headings,
        },
        "action_summary": (
            f"Added {len(added_elements)} elements, removed {len(removed_elements)} elements, "
            f"changed headings +{len(added_headings)}/-{len(removed_headings)}"
        ),
    }


def _prime_wiki_stats_payload() -> dict:
    records = _load_all_prime_wiki_snapshots()
    total_compressed_bytes = 0
    domains: set[str] = set()
    last_24h_count = 0
    cutoff = time.time() - 86400
    for record in records:
        compressed_size_bytes = record.get("compressed_size_bytes", 0)
        if isinstance(compressed_size_bytes, int):
            total_compressed_bytes += compressed_size_bytes
        domain = record.get("domain", "")
        if isinstance(domain, str) and domain:
            domains.add(domain)
        captured_at_ts = record.get("captured_at_ts", 0)
        if isinstance(captured_at_ts, (int, float)) and captured_at_ts >= cutoff:
            last_24h_count += 1
    return {
        "total_snapshots": len(records),
        "total_compressed_kb": round(total_compressed_bytes / 1024, 2),
        "domains_covered": len(domains),
        "last_24h_count": last_24h_count,
    }


def _prime_wiki_sync_enabled_for_tier(user_tier: str) -> bool:
    return _MARKETPLACE_TIER_RANKS.get(user_tier, 0) >= _MARKETPLACE_TIER_RANKS["pro"]


def _prime_wiki_cloud_push_worker(snapshot_record: dict) -> None:
    request = urllib.request.Request(
        PRIME_WIKI_PUSH_URL,
        data=json.dumps(snapshot_record).encode(),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    try:
        with _prime_wiki_urlopen(request, timeout=PRIME_WIKI_PUSH_TIMEOUT_SECONDS) as response:
            response.read()
        record_evidence(
            "prime_wiki_cloud_push_succeeded",
            {
                "snapshot_id": snapshot_record.get("snapshot_id", ""),
                "url_hash": snapshot_record.get("url_hash", ""),
            },
        )
    except urllib.error.HTTPError as exc:
        record_evidence(
            "prime_wiki_cloud_push_failed",
            {
                "snapshot_id": snapshot_record.get("snapshot_id", ""),
                "url_hash": snapshot_record.get("url_hash", ""),
                "status": exc.code,
            },
        )
    except urllib.error.URLError as exc:
        record_evidence(
            "prime_wiki_cloud_push_failed",
            {
                "snapshot_id": snapshot_record.get("snapshot_id", ""),
                "url_hash": snapshot_record.get("url_hash", ""),
                "reason": str(exc.reason) if hasattr(exc, "reason") else str(exc),
            },
        )
    except OSError as exc:
        record_evidence(
            "prime_wiki_cloud_push_failed",
            {
                "snapshot_id": snapshot_record.get("snapshot_id", ""),
                "url_hash": snapshot_record.get("url_hash", ""),
                "reason": str(exc),
            },
        )


def _queue_prime_wiki_cloud_push(snapshot_record: dict) -> bool:
    user_tier = _load_account_tier()
    if not _prime_wiki_sync_enabled_for_tier(user_tier):
        return False
    thread = threading.Thread(
        target=_prime_wiki_cloud_push_worker,
        args=(snapshot_record,),
        daemon=True,
    )
    thread.start()
    return True


def _default_local_apps_root() -> Path:
    return Path.home() / ".solace" / "apps"


def _local_apps_root_path() -> Path:
    settings = _load_settings()
    configured = settings.get("local_apps_root")
    if isinstance(configured, str) and configured.strip():
        return Path(configured).expanduser().resolve()
    env_value = os.environ.get("SOLACE_LOCAL_APPS_ROOT", "").strip()
    if env_value:
        return Path(env_value).expanduser().resolve()
    return _default_local_apps_root().resolve()


def _source_app_roots(repo_root: str) -> tuple[Path, ...]:
    settings = _load_settings()
    roots: list[Path] = []
    configured = settings.get("app_source_roots")
    if isinstance(configured, list):
        for entry in configured:
            if isinstance(entry, str) and entry.strip():
                roots.append(Path(entry).expanduser().resolve())
    env_value = os.environ.get("SOLACE_APP_SOURCE_ROOTS", "").strip()
    if env_value:
        for entry in env_value.split(os.pathsep):
            if entry.strip():
                roots.append(Path(entry).expanduser().resolve())
    defaults = (
        Path(repo_root).resolve().parent / "solace-cli" / "data" / "default" / "apps",
        Path(repo_root).resolve() / "data" / "default" / "apps",
    )
    roots.extend(defaults)
    seen: set[Path] = set()
    resolved: list[Path] = []
    for root in roots:
        if root in seen:
            continue
        seen.add(root)
        if root.is_dir():
            resolved.append(root)
    return tuple(resolved)


def _source_domain_roots(repo_root: str) -> tuple[Path, ...]:
    settings = _load_settings()
    roots: list[Path] = []
    configured = settings.get("domain_source_roots")
    if isinstance(configured, list):
        for entry in configured:
            if isinstance(entry, str) and entry.strip():
                roots.append(Path(entry).expanduser().resolve())
    env_value = os.environ.get("SOLACE_DOMAIN_SOURCE_ROOTS", "").strip()
    if env_value:
        for entry in env_value.split(os.pathsep):
            if entry.strip():
                roots.append(Path(entry).expanduser().resolve())
    defaults = (
        Path(repo_root).resolve().parent / "solace-cli" / "data" / "default" / "domains",
        Path(repo_root).resolve() / "data" / "default" / "domains",
    )
    roots.extend(defaults)
    seen: set[Path] = set()
    resolved: list[Path] = []
    for root in roots:
        if root in seen:
            continue
        seen.add(root)
        if root.is_dir():
            resolved.append(root)
    return tuple(resolved)


def _iter_app_dirs_under(root: Path) -> list[Path]:
    if not root.is_dir():
        return []
    found: dict[Path, Path] = {}
    for manifest_path in root.glob("*/manifest.yaml"):
        found[manifest_path.parent.resolve()] = manifest_path.parent.resolve()
    for manifest_path in root.glob("*/*/manifest.yaml"):
        found[manifest_path.parent.resolve()] = manifest_path.parent.resolve()
    return sorted(found.values())


def _manifest_records_from_roots(roots: tuple[Path, ...]) -> list[tuple[str, dict, Path]]:
    manifests: list[tuple[str, dict, Path]] = []
    seen: set[str] = set()
    for apps_root in roots:
        for app_dir in _iter_app_dirs_under(apps_root):
            app_id = app_dir.name
            if app_id in seen:
                continue
            manifest_path = app_dir / "manifest.yaml"
            try:
                raw_manifest = yaml.safe_load(manifest_path.read_text())
            except FileNotFoundError:
                continue
            except OSError:
                continue
            except yaml.YAMLError:
                continue
            if isinstance(raw_manifest, dict):
                manifests.append((app_id, raw_manifest, manifest_path))
                seen.add(app_id)
    manifests.sort(key=lambda item: item[0])
    return manifests


def _store_suggestions_root() -> Path:
    env_value = os.environ.get("SOLACE_STORE_SUGGESTIONS_ROOT", "").strip()
    if env_value:
        return Path(env_value).expanduser().resolve()
    return (Path.home() / ".solace" / "store-suggestions").resolve()


def _domain_requires_login_flag(manifest: dict[str, Any]) -> bool:
    return bool(manifest.get("login_required", manifest.get("requires_login", False)))


def _scan_apps_in_domain(domain_apps_root: Path) -> list[dict[str, Any]]:
    apps: list[dict[str, Any]] = []
    if not domain_apps_root.is_dir():
        return apps
    for app_dir in sorted(domain_apps_root.iterdir()):
        if not app_dir.is_dir():
            continue
        manifest_path = app_dir / "manifest.yaml"
        if not manifest_path.is_file():
            continue
        try:
            raw_manifest = yaml.safe_load(manifest_path.read_text(encoding="utf-8"))
        except OSError:
            continue
        except yaml.YAMLError:
            continue
        if not isinstance(raw_manifest, dict):
            continue
        app_payload = dict(raw_manifest)
        app_payload.setdefault("id", app_dir.name)
        apps.append(app_payload)
    return apps


def _apps_list_from_domain_manifest(manifest: dict[str, Any]) -> list[dict[str, Any]]:
    raw_apps = manifest.get("apps", [])
    if not isinstance(raw_apps, list):
        return []
    apps: list[dict[str, Any]] = []
    for entry in raw_apps:
        if isinstance(entry, str) and _APP_ID_RE.fullmatch(entry):
            apps.append({"id": entry})
    return apps


def _scan_domains_dirs(roots: tuple[Path, ...]) -> list[dict[str, Any]]:
    """Scan domain directories and return merged domain dicts."""
    domains: dict[str, dict[str, Any]] = {}
    for root in roots:
        if not root.is_dir():
            continue
        for domain_dir in sorted(root.iterdir()):
            if not domain_dir.is_dir():
                continue
            manifest_path = domain_dir / "manifest.yaml"
            if not manifest_path.is_file():
                continue
            try:
                raw_manifest = yaml.safe_load(manifest_path.read_text(encoding="utf-8"))
            except OSError:
                continue
            except yaml.YAMLError:
                continue
            if not isinstance(raw_manifest, dict):
                continue
            domain_id = _normalize_domain(domain_dir.name)
            if not domain_id:
                continue
            apps = _scan_apps_in_domain(domain_dir / "apps")
            if not apps:
                apps = _apps_list_from_domain_manifest(raw_manifest)
            domain_payload = dict(raw_manifest)
            domain_payload["id"] = domain_id
            domain_payload["domain"] = domain_id
            domain_payload["apps"] = apps
            domain_payload["app_count"] = len(apps)
            domain_payload["login_required"] = _domain_requires_login_flag(domain_payload)
            domain_payload["source_dir"] = str(domain_dir)
            domains[domain_id] = domain_payload
    return [domains[key] for key in sorted(domains)]


def _handle_domains_bootstrap(default_only: bool = False) -> dict[str, Any]:
    domains_root = Path("/home/phuc/projects/solace-cli/data/default/domains")
    target_root = Path.home() / ".solace" / "apps"
    bootstrapped_domains = 0
    bootstrapped_apps = 0
    domain_ids: list[str] = []
    for domain_dir in sorted(domains_root.iterdir()):
        if not domain_dir.is_dir():
            continue
        manifest_path = domain_dir / "manifest.yaml"
        try:
            manifest = yaml.safe_load(manifest_path.read_text(encoding="utf-8"))
        except FileNotFoundError:
            continue
        except yaml.YAMLError:
            continue
        if not isinstance(manifest, dict):
            continue
        if _domain_requires_login_flag(manifest):
            continue
        if default_only and not bool(manifest.get("default_install", False)):
            continue
        domain_id = str(manifest.get("id") or domain_dir.name).strip()
        raw_apps = manifest.get("apps", [])
        domain_apps = raw_apps if isinstance(raw_apps, list) else []
        domain_target = target_root / domain_id
        try:
            domain_target.mkdir(parents=True, exist_ok=True)
            shutil.copy2(str(manifest_path), str(domain_target / "manifest.yaml"))
            for app_entry in domain_apps:
                app_id = app_entry.get("id") if isinstance(app_entry, dict) else app_entry
                if isinstance(app_id, str) and _APP_ID_RE.fullmatch(app_id):
                    (domain_target / "apps" / app_id).mkdir(parents=True, exist_ok=True)
        except OSError as exc:
            raise RuntimeError(f"Bootstrap failed for {domain_id}: {exc}") from exc
        bootstrapped_domains += 1
        bootstrapped_apps += sum(
            1
            for app_entry in domain_apps
            if isinstance(app_entry.get("id") if isinstance(app_entry, dict) else app_entry, str)
            and _APP_ID_RE.fullmatch(app_entry.get("id") if isinstance(app_entry, dict) else app_entry)
        )
        domain_ids.append(domain_id)
    return {
        "bootstrapped_domains": bootstrapped_domains,
        "bootstrapped_apps": bootstrapped_apps,
        "domains": domain_ids,
    }


def _marketplace_apps_root(repo_root: str) -> Path:
    return _local_apps_root_path()


def _marketplace_app_dir(repo_root: str, app_id: str) -> Path:
    app_dir = _local_app_dir(repo_root, app_id)
    if app_dir is not None:
        return app_dir
    return _marketplace_apps_root(repo_root) / app_id


def _session_rules_path_for_app(repo_root: str, app_id: str) -> Path:
    return _marketplace_app_dir(repo_root, app_id) / "session-rules.yaml"


def _custom_app_ids(repo_root: str) -> set[str]:
    app_ids: set[str] = set()
    for app_id, manifest, _manifest_path in _iter_local_manifest_records(repo_root):
        if bool(manifest.get("custom", False)):
            app_ids.add(app_id)
    return app_ids


def _installed_app_ids(repo_root: str) -> set[str]:
    return {app_id for app_id, _manifest, _manifest_path in _iter_local_manifest_records(repo_root)}


def _preferred_domain_for_manifest(manifest: dict) -> str:
    try:
        patterns = _manifest_domain_patterns(manifest, str(manifest.get("site", "")))
    except ValueError:
        patterns = []
    if patterns:
        host, _path = _split_domain_pattern(patterns[0])
        normalized = _normalize_domain(host)
        if normalized:
            return normalized
    fallback = _normalize_domain(str(manifest.get("site") or ""))
    return fallback or "misc.local"


def _local_app_target_dir(app_id: str, manifest: dict) -> Path:
    return _local_apps_root_path() / _preferred_domain_for_manifest(manifest) / app_id


def _local_app_dir(repo_root: str, app_id: str) -> Optional[Path]:
    for found_app_id, _manifest, manifest_path in _iter_local_manifest_records(repo_root):
        if found_app_id == app_id:
            return manifest_path.parent
    return None


def _source_app_dir(repo_root: str, app_id: str) -> Optional[Path]:
    for found_app_id, _manifest, manifest_path in _iter_source_manifest_records(repo_root):
        if found_app_id == app_id:
            return manifest_path.parent
    return None


def _materialize_app_from_source(repo_root: str, app_id: str) -> Path:
    source_dir = _source_app_dir(repo_root, app_id)
    if source_dir is None:
        raise FileNotFoundError("app not found in source roots")
    manifest = _load_manifest_for_app(repo_root, app_id)
    if not manifest:
        raise FileNotFoundError("app manifest not found")
    target_dir = _local_app_target_dir(app_id, manifest)
    if target_dir.is_dir():
        return target_dir
    target_dir.parent.mkdir(parents=True, exist_ok=True)
    shutil.copytree(source_dir, target_dir)
    return target_dir


def _remove_local_app_materialization(repo_root: str, app_id: str) -> None:
    app_dir = _local_app_dir(repo_root, app_id)
    if app_dir is None:
        return
    shutil.rmtree(app_dir)


def _set_app_installed(repo_root: str, app_id: str, installed: bool) -> None:
    if installed:
        _materialize_app_from_source(repo_root, app_id)
    else:
        _remove_local_app_materialization(repo_root, app_id)


def _is_marketplace_app_installed(repo_root: str, app_id: str) -> bool:
    return app_id in _installed_app_ids(repo_root)


def _normalize_marketplace_app(raw_app: dict, repo_root: str) -> Optional[dict]:
    app_id = raw_app.get("app_id") or raw_app.get("id")
    if not isinstance(app_id, str) or not _APP_ID_RE.fullmatch(app_id):
        return None
    display_name = raw_app.get("display_name") or raw_app.get("name") or app_id.replace("-", " ").title()
    description = raw_app.get("description", "")
    category = raw_app.get("category", "solace")
    tier_required = raw_app.get("tier_required") or raw_app.get("tier") or "free"
    version = raw_app.get("version", "")
    icon_url = raw_app.get("icon_url", "")
    if not isinstance(display_name, str):
        display_name = app_id.replace("-", " ").title()
    if not isinstance(description, str):
        description = ""
    if not isinstance(category, str) or not category:
        category = "solace"
    if not isinstance(tier_required, str):
        tier_required = "free"
    normalized_tier = tier_required.strip().lower()
    if normalized_tier not in _MARKETPLACE_TIER_RANKS:
        normalized_tier = "free"
    if not isinstance(version, str):
        version = ""
    if not isinstance(icon_url, str):
        icon_url = ""
    return {
        "app_id": app_id,
        "display_name": display_name,
        "description": description,
        "category": category,
        "tier_required": normalized_tier,
        "installed": _is_marketplace_app_installed(repo_root, app_id),
        "version": version,
        "icon_url": icon_url,
    }


def _normalize_marketplace_apps(raw_apps: list, repo_root: str) -> list[dict]:
    apps: list[dict] = []
    for raw_app in raw_apps:
        if not isinstance(raw_app, dict):
            continue
        normalized = _normalize_marketplace_app(raw_app, repo_root)
        if normalized is not None:
            apps.append(normalized)
    return apps


def _write_marketplace_cache(raw_apps: list) -> None:
    payload = {
        "apps": raw_apps,
        "total": len(raw_apps),
        "fetched_at": int(time.time()),
    }
    MARKETPLACE_CACHE_PATH.parent.mkdir(parents=True, exist_ok=True)
    MARKETPLACE_CACHE_PATH.write_text(json.dumps(payload, indent=2))


def _load_marketplace_cache(repo_root: str) -> tuple[Optional[list[dict]], str]:
    if not MARKETPLACE_CACHE_PATH.exists():
        return None, ""
    try:
        payload = json.loads(MARKETPLACE_CACHE_PATH.read_text())
    except json.JSONDecodeError:
        return None, ""
    except OSError:
        return None, ""
    if not isinstance(payload, dict):
        return None, ""
    raw_apps = payload.get("apps", [])
    if not isinstance(raw_apps, list):
        return None, ""
    fetched_at = payload.get("fetched_at")
    if not isinstance(fetched_at, (int, float)):
        try:
            fetched_at = MARKETPLACE_CACHE_PATH.stat().st_mtime
        except OSError:
            fetched_at = 0
    age_seconds = time.time() - float(fetched_at)
    source = "cache" if age_seconds <= MARKETPLACE_CACHE_TTL_SECONDS else "stale_cache"
    return _normalize_marketplace_apps(raw_apps, repo_root), source


def _load_local_marketplace_catalog(repo_root: str) -> list[dict]:
    raw_apps: list[dict] = []
    for entry in _load_official_store_apps(repo_root):
        raw_apps.append({
            "app_id": entry.get("id", ""),
            "display_name": entry.get("name", ""),
            "description": entry.get("description", ""),
            "category": entry.get("category", "solace"),
            "tier_required": entry.get("tier_required", "free"),
            "version": "1.0.0",
            "icon_url": "",
        })
    return _normalize_marketplace_apps(raw_apps, repo_root)


def _fetch_marketplace_catalog(repo_root: str) -> tuple[Optional[list[dict]], str]:
    local_apps = _load_local_marketplace_catalog(repo_root)
    if local_apps:
        return local_apps, "local_bundle"
    with _MARKETPLACE_LOCK:
        try:
            with _marketplace_urlopen(MARKETPLACE_CATALOG_URL, timeout=MARKETPLACE_TIMEOUT_SECONDS) as response:
                payload = json.loads(response.read().decode())
        except urllib.error.URLError as exc:
            record_evidence("marketplace_catalog_fetch_failed", {
                "url": MARKETPLACE_CATALOG_URL,
                "reason": str(exc.reason) if hasattr(exc, "reason") else str(exc),
            })
            apps, source = _load_marketplace_cache(repo_root)
            if apps is not None:
                return apps, source
            local_apps = _load_local_marketplace_catalog(repo_root)
            return (local_apps, "local_bundle") if local_apps else (None, "")
        except json.JSONDecodeError as exc:
            record_evidence("marketplace_catalog_fetch_failed", {
                "url": MARKETPLACE_CATALOG_URL,
                "reason": str(exc),
            })
            apps, source = _load_marketplace_cache(repo_root)
            if apps is not None:
                return apps, source
            local_apps = _load_local_marketplace_catalog(repo_root)
            return (local_apps, "local_bundle") if local_apps else (None, "")
        except OSError as exc:
            record_evidence("marketplace_catalog_fetch_failed", {
                "url": MARKETPLACE_CATALOG_URL,
                "reason": str(exc),
            })
            apps, source = _load_marketplace_cache(repo_root)
            if apps is not None:
                return apps, source
            local_apps = _load_local_marketplace_catalog(repo_root)
            return (local_apps, "local_bundle") if local_apps else (None, "")
        raw_apps = payload.get("apps", []) if isinstance(payload, dict) else []
        if not isinstance(raw_apps, list):
            raw_apps = []
        try:
            _write_marketplace_cache(raw_apps)
        except OSError as exc:
            record_evidence("marketplace_cache_write_failed", {
                "path": str(MARKETPLACE_CACHE_PATH),
                "reason": str(exc),
            })
        return _normalize_marketplace_apps(raw_apps, repo_root), "remote"


def _find_marketplace_app(apps: list[dict], app_id: str) -> Optional[dict]:
    for app in apps:
        if app.get("app_id") == app_id:
            return app
    return None


def _tier_allows_install(user_tier: str, tier_required: str) -> bool:
    return _MARKETPLACE_TIER_RANKS[user_tier] >= _MARKETPLACE_TIER_RANKS[tier_required]


def _download_marketplace_session_rules(app_id: str, repo_root: str) -> tuple[Optional[str], Optional[int], str]:
    local_rules_path = _repo_session_rules_path_for_app(repo_root, app_id)
    if local_rules_path is not None:
        try:
            return local_rules_path.read_text(), None, "local_bundle"
        except OSError:
            pass
    url = MARKETPLACE_APP_RULES_URL_TEMPLATE.format(app_id=app_id)
    try:
        with _marketplace_urlopen(url, timeout=MARKETPLACE_TIMEOUT_SECONDS) as response:
            return response.read().decode(), None, "remote"
    except urllib.error.URLError as exc:
        if getattr(exc, "code", None) == 404:
            return None, 404, "remote"
        raise


def _normalized_cloud_twin_settings(raw_value: object) -> dict:
    settings = dict(DEFAULT_CLOUD_TWIN_SETTINGS)
    if not isinstance(raw_value, dict):
        return settings
    url = raw_value.get("url", "")
    enabled = raw_value.get("enabled", settings["enabled"])
    prefer_cloud = raw_value.get("prefer_cloud", settings["prefer_cloud"])
    fallback_to_local = raw_value.get("fallback_to_local", settings["fallback_to_local"])
    settings["url"] = url if isinstance(url, str) else ""
    settings["enabled"] = enabled if isinstance(enabled, bool) else DEFAULT_CLOUD_TWIN_SETTINGS["enabled"]
    settings["prefer_cloud"] = prefer_cloud if isinstance(prefer_cloud, bool) else DEFAULT_CLOUD_TWIN_SETTINGS["prefer_cloud"]
    settings["fallback_to_local"] = (
        fallback_to_local
        if isinstance(fallback_to_local, bool)
        else DEFAULT_CLOUD_TWIN_SETTINGS["fallback_to_local"]
    )
    return settings


def _normalize_runtime_locale(raw_value: object) -> str:
    if not isinstance(raw_value, str):
        return "en"
    normalized = raw_value.strip().lower()
    if normalized in SUPPORTED_RUNTIME_LOCALES:
        return normalized
    return "en"


def _runtime_locale_direction(locale: str) -> str:
    return "rtl" if locale in RTL_RUNTIME_LOCALES else "ltr"


def _current_runtime_locale(settings: Optional[dict[str, Any]] = None) -> str:
    source = settings if isinstance(settings, dict) else _load_settings()
    return _normalize_runtime_locale(source.get("locale", "en"))


def _localized_solaceagi_url(url: str, locale: Optional[str] = None) -> str:
    trimmed = str(url or "").strip()
    if not trimmed:
        return trimmed
    parsed = urllib.parse.urlparse(trimmed)
    if parsed.scheme not in ("http", "https"):
        return trimmed
    host = parsed.netloc.lower()
    if host not in {"solaceagi.com", "www.solaceagi.com"}:
        return trimmed
    chosen_locale = _normalize_runtime_locale(locale or _current_runtime_locale())
    if chosen_locale == "en":
        return trimmed
    path = parsed.path or "/"
    if path == f"/{chosen_locale}" or path.startswith(f"/{chosen_locale}/"):
        return trimmed
    localized_path = f"/{chosen_locale}" if path == "/" else f"/{chosen_locale}{path}"
    return urllib.parse.urlunparse(parsed._replace(path=localized_path))


def _load_settings() -> dict:
    try:
        settings = json.loads(SETTINGS_PATH.read_text())
    except FileNotFoundError:
        settings = {}
    except json.JSONDecodeError:
        settings = {}
    except OSError:
        settings = {}
    if not isinstance(settings, dict):
        settings = {}
    merged = dict(settings)
    merged["cloud_twin"] = _normalized_cloud_twin_settings(settings.get("cloud_twin", {}))
    merged["locale"] = _normalize_runtime_locale(settings.get("locale", "en"))
    return merged


def _save_settings(settings: dict) -> None:
    persisted = dict(settings)
    persisted["cloud_twin"] = _normalized_cloud_twin_settings(settings.get("cloud_twin", {}))
    persisted["locale"] = _normalize_runtime_locale(settings.get("locale", "en"))
    SETTINGS_PATH.parent.mkdir(parents=True, exist_ok=True)
    SETTINGS_PATH.write_text(json.dumps(persisted, indent=2))


def _legacy_account_tier_from_settings() -> str:
    try:
        settings = json.loads(SETTINGS_PATH.read_text())
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return "free"
    if not isinstance(settings, dict):
        return "free"
    user = settings.get("user", {})
    if isinstance(user, dict):
        tier = user.get("tier")
        if isinstance(tier, str):
            normalized = tier.strip().lower()
            if normalized in _MARKETPLACE_TIER_RANKS:
                return normalized
    account = settings.get("account", {})
    if not isinstance(account, dict):
        return "free"
    tier = account.get("tier", "free")
    if not isinstance(tier, str):
        return "free"
    normalized = tier.strip().lower()
    if normalized not in _MARKETPLACE_TIER_RANKS:
        return "free"
    return normalized


def _normalize_membership_tier(value: object, default: str = "free") -> str:
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized in _MARKETPLACE_TIER_RANKS:
            return normalized
    return default


def _normalize_model_source(value: object) -> Optional[str]:
    if isinstance(value, str):
        normalized = value.strip().lower()
        aliases = {
            "local_cli": "cli",
            "cli_wrapper": "cli",
            "managed_llm": "managed",
            "managed_solace_agi": "managed",
        }
        normalized = aliases.get(normalized, normalized)
        if normalized in _MODEL_SOURCES:
            return normalized
    return None


def _normalize_model_sources(value: object) -> list[str]:
    if isinstance(value, str):
        normalized = _normalize_model_source(value)
        return [normalized] if normalized else []
    if not isinstance(value, list):
        return []
    seen: set[str] = set()
    normalized_values: list[str] = []
    for entry in value:
        normalized = _normalize_model_source(entry)
        if normalized and normalized not in seen:
            normalized_values.append(normalized)
            seen.add(normalized)
    return normalized_values


def _primary_model_source(model_sources: list[str], managed_llm_enabled: bool, fallback: Optional[str] = None) -> Optional[str]:
    if managed_llm_enabled and "managed" in model_sources:
        return "managed"
    for candidate in _MODEL_SOURCE_PREFERENCE:
        if candidate in model_sources:
            return candidate
    return _normalize_model_source(fallback)


def _default_device_id() -> str:
    return "hub_" + uuid.uuid5(uuid.NAMESPACE_DNS, str(Path.home().resolve())).hex[:16]


def _ollama_config_payload(settings: Optional[dict] = None) -> dict[str, Any]:
    source = settings if isinstance(settings, dict) else _load_settings()
    raw = source.get("ollama", {})
    if not isinstance(raw, dict):
        raw = {}
    url = raw.get("url", "")
    if not isinstance(url, str):
        url = ""
    normalized_url = url.strip().rstrip("/")
    return {
        "configured": bool(normalized_url),
        "url": normalized_url,
    }


def _cli_detected_snapshot() -> dict[str, dict[str, Any]]:
    detected: dict[str, dict[str, Any]] = {}
    for tool in SUPPORTED_CLI_TOOLS:
        path = shutil.which(tool)
        detected[tool] = {"installed": path is not None, "path": path or ""}
    return detected


def _save_ollama_config(url: str) -> dict[str, Any]:
    candidate = str(url or "").strip().rstrip("/")
    parsed = urllib.parse.urlparse(candidate)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("ollama url must start with http:// or https:// and include a host")
    settings = _load_settings()
    settings["ollama"] = {"url": candidate}
    _save_settings(settings)
    return {"configured": True, "url": candidate}


def _test_ollama_url(url: str) -> dict[str, Any]:
    payload = _save_ollama_config(url)
    request = urllib.request.Request(f"{payload['url']}/api/tags", method="GET")
    started = time.perf_counter()
    try:
        with urllib.request.urlopen(request, timeout=5) as response:
            body = json.loads(response.read().decode("utf-8") or "{}")
    except urllib.error.URLError as exc:
        raise ValueError(f"ollama unreachable: {exc}") from exc
    except json.JSONDecodeError as exc:
        raise ValueError("ollama returned invalid json") from exc
    models = body.get("models", [])
    return {
        "status": "reachable",
        "url": payload["url"],
        "models": len(models) if isinstance(models, list) else 0,
        "latency_ms": int((time.perf_counter() - started) * 1000),
    }


def _load_domain_events() -> list[dict[str, Any]]:
    if not DOMAIN_EVENTS_PATH.exists():
        return []
    try:
        payload = json.loads(DOMAIN_EVENTS_PATH.read_text())
    except (json.JSONDecodeError, OSError):
        return []
    return payload if isinstance(payload, list) else []


def _save_domain_events(events: list[dict[str, Any]]) -> None:
    DOMAIN_EVENTS_PATH.parent.mkdir(parents=True, exist_ok=True)
    DOMAIN_EVENTS_PATH.write_text(json.dumps(events, indent=2))


def _append_domain_event(
    domain: str,
    event_type: str,
    title: str,
    summary: str,
    *,
    app_id: str = "",
    detail_url: str = "",
    report_url: str = "",
    requires_signoff: bool = False,
    metadata: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    event = {
        "id": "evt_" + uuid.uuid4().hex[:16],
        "domain": _normalize_domain(domain) or "solaceagi.com",
        "type": event_type,
        "title": title[:128],
        "summary": summary[:512],
        "app_id": app_id,
        "detail_url": detail_url,
        "report_url": report_url,
        "requires_signoff": bool(requires_signoff),
        "metadata": dict(metadata or {}),
        "ts": int(time.time()),
    }
    events = _load_domain_events()
    events.append(event)
    if len(events) > 500:
        events = events[-500:]
    _save_domain_events(events)
    return event


def _normalize_domain_event_payload(event: dict[str, Any]) -> dict[str, Any]:
    payload = dict(event or {})
    event_type = str(payload.get("event_type") or payload.get("type") or "").strip()
    if event_type:
        payload["event_type"] = event_type
        payload["type"] = event_type
    event_id = str(payload.get("id") or "").strip()
    if event_id:
        payload["detail_url"] = str(payload.get("detail_url") or f"/events/{event_id}")
        payload["api_url"] = str(payload.get("api_url") or f"/api/v1/events/{event_id}")
    payload["report_available"] = bool(payload.get("report_url"))
    payload["signoff_required"] = bool(payload.get("requires_signoff", False))
    return payload


def _find_domain_event(event_id: str) -> Optional[dict[str, Any]]:
    wanted = str(event_id or "").strip()
    if not wanted:
        return None
    return next((item for item in _load_domain_events() if str(item.get("id")) == wanted), None)


def _load_domain_profiles() -> dict[str, dict[str, Any]]:
    settings = _load_settings()
    profiles = settings.get("domains", {})
    return profiles if isinstance(profiles, dict) else {}


def _save_domain_profiles(profiles: dict[str, dict[str, Any]]) -> None:
    settings = _load_settings()
    settings["domains"] = profiles
    _save_settings(settings)


def _domain_requires_login(domain: str) -> bool:
    normalized = _normalize_domain(domain)
    return normalized in {"mail.google.com", "calendar.google.com", "www.linkedin.com", "app.slack.com"}


def _is_keepalive_app(app_id: str, domain: str) -> bool:
    normalized = _normalize_domain(domain)
    if app_id in {"morning-brief", "google-search-mission", "solace-yinyang"}:
        return True
    if normalized == "mail.google.com":
        return "gmail" in app_id or "mail" in app_id
    if normalized == "calendar.google.com":
        return "calendar" in app_id
    if normalized == "www.linkedin.com":
        return "linkedin" in app_id
    if normalized == "app.slack.com":
        return "slack" in app_id or "message" in app_id
    return False


def _default_domain_profile(repo_root: str, domain: str) -> dict[str, Any]:
    normalized = _normalize_domain(domain)
    selected: list[str] = []
    keepalive: list[str] = []
    requires_login = _domain_requires_login(normalized)
    active = False
    login_url = {
        "mail.google.com": "https://mail.google.com/",
        "calendar.google.com": "https://calendar.google.com/",
        "www.linkedin.com": "https://www.linkedin.com/feed/",
        "app.slack.com": "https://app.slack.com/",
    }.get(normalized, "")
    success_url = login_url or {
        "solaceagi.com": "https://solaceagi.com/dashboard",
        "www.google.com": "https://www.google.com/",
        "google.com": "https://www.google.com/",
        "news.google.com": "https://news.google.com/",
    }.get(normalized, "")
    return {
        "domain": normalized,
        "selected_apps": selected,
        "keepalive_apps": keepalive,
        "active": active,
        "requires_login": requires_login,
        "login_url": login_url,
        "success_url": success_url,
        "session_policy": dict(DEFAULT_DOMAIN_SESSION_POLICY, success_url=success_url),
        "budgets": {},
        "default_schedule": "",
        "last_activated_at": int(time.time()) if active else None,
    }


def _ensure_default_domain_profiles(repo_root: str) -> dict[str, dict[str, Any]]:
    profiles = _load_domain_profiles()
    changed = False
    for domain in ("solaceagi.com", "www.google.com"):
        normalized = _normalize_domain(domain)
        if normalized not in profiles:
            profiles[normalized] = _default_domain_profile(repo_root, normalized)
            changed = True
    if changed:
        _save_domain_profiles(profiles)
    return profiles


def _domain_status_payload(repo_root: str, domain: str) -> dict[str, Any]:
    normalized = _normalize_domain(domain)
    profiles = _load_domain_profiles()
    profile = profiles.get(normalized)
    if not isinstance(profile, dict):
        profile = _default_domain_profile(repo_root, normalized)
        profiles[normalized] = profile
        _save_domain_profiles(profiles)
    payload = _apps_for_domain(repo_root, normalized, "/", _load_account_tier())
    apps = payload.get("apps", []) if isinstance(payload, dict) else []
    selected = set(str(item) for item in profile.get("selected_apps", []))
    keepalive = set(str(item) for item in profile.get("keepalive_apps", []))
    events = _load_domain_events()
    filtered = events if normalized == "solaceagi.com" else [event for event in events if event.get("domain") == normalized]
    filtered = [_normalize_domain_event_payload(event) for event in filtered]
    return {
        "domain": normalized,
        "active": bool(profile.get("active", False)),
        "requires_login": bool(profile.get("requires_login", False)),
        "login_url": str(profile.get("login_url", "")),
        "success_url": str(profile.get("success_url", "")),
        "session_policy": dict(profile.get("session_policy", {})),
        "budgets": dict(profile.get("budgets", {})),
        "default_schedule": str(profile.get("default_schedule", "")),
        "selected_apps": list(selected),
        "keepalive_apps": list(keepalive),
        "event_count": len(filtered),
        "events": filtered[:20],
        "apps": [
            {
                **app,
                "selected": str(app.get("id") or app.get("app_id") or "") in selected,
                "keepalive": str(app.get("id") or app.get("app_id") or "") in keepalive,
                "keepalive_capable": _is_keepalive_app(str(app.get("id") or app.get("app_id") or ""), normalized),
            }
            for app in apps
            if isinstance(app, dict)
        ],
    }


def _domain_status_summary_payload(
    repo_root: str,
    domain: str,
    *,
    profiles: Optional[dict[str, Any]] = None,
    events: Optional[list[dict[str, Any]]] = None,
) -> dict[str, Any]:
    normalized = _normalize_domain(domain)
    profile_map = profiles if isinstance(profiles, dict) else _load_domain_profiles()
    profile = profile_map.get(normalized)
    if not isinstance(profile, dict):
        profile = _default_domain_profile(repo_root, normalized)
    event_rows = events if isinstance(events, list) else _load_domain_events()
    filtered = event_rows if normalized == "solaceagi.com" else [event for event in event_rows if event.get("domain") == normalized]
    return {
        "domain": normalized,
        "active": bool(profile.get("active", False)),
        "requires_login": bool(profile.get("requires_login", False)),
        "selected_apps": list(profile.get("selected_apps", [])),
        "keepalive_apps": list(profile.get("keepalive_apps", [])),
        "event_count": len(filtered),
    }


def _bootstrap_starter_domains(repo_root: str) -> dict[str, dict[str, Any]]:
    profiles = _ensure_default_domain_profiles(repo_root)
    changed = False
    for domain, preferred_apps in {
        "solaceagi.com": ["morning-brief", "solace-yinyang", "agi-dashboard"],
        "www.google.com": ["google-search-mission", "competitor-watch", "google-search-trends"],
    }.items():
        normalized = _normalize_domain(domain)
        profile = profiles.get(normalized)
        if not isinstance(profile, dict):
            profile = _default_domain_profile(repo_root, normalized)
            profiles[normalized] = profile
            changed = True
        selected_apps = list(profile.get("selected_apps", []))
        keepalive_apps = list(profile.get("keepalive_apps", []))
        for app_id in preferred_apps:
            try:
                _set_app_installed(repo_root, app_id, True)
            except OSError:
                continue
            if app_id not in selected_apps:
                selected_apps.append(app_id)
                changed = True
            if _is_keepalive_app(app_id, normalized) and app_id not in keepalive_apps:
                keepalive_apps.append(app_id)
                changed = True
        profile["selected_apps"] = selected_apps
        profile["keepalive_apps"] = keepalive_apps
        profile["active"] = not bool(profile.get("requires_login", False))
        if profile["active"]:
            profile["last_activated_at"] = int(time.time())
        profiles[normalized] = profile
    if changed:
        _save_domain_profiles(profiles)
    return profiles


def _domain_label_for_host(domain: str) -> str:
    normalized = _normalize_domain(domain)
    labels = {
        "solaceagi.com": "Solace AGI",
        "google.com": "Google Search",
        "mail.google.com": "Gmail",
        "calendar.google.com": "Calendar",
        "www.linkedin.com": "LinkedIn",
        "app.slack.com": "Slack",
    }
    if normalized in labels:
        return labels[normalized]
    bare = normalized.replace(".com", "").replace(".org", "").replace(".net", "")
    parts = [part for part in re.split(r"[\.-]+", bare) if part and part not in {"www", "app"}]
    if not parts:
        return normalized or "Domain"
    return " ".join(part.capitalize() for part in parts)


def _domain_icon_for_host(domain: str) -> str:
    normalized = _normalize_domain(domain)
    icons = {
        "solaceagi.com": "/branding/yinyang-rotating.gif",
        "google.com": "/branding/apps/google-search.png",
        "mail.google.com": "/branding/apps/gmail.jpg",
        "calendar.google.com": "/branding/apps/google-calendar.png",
        "www.linkedin.com": "/branding/apps/linkedin.png",
        "app.slack.com": "/branding/apps/slack.png",
    }
    return icons.get(normalized, "/branding/yinyang-rotating.gif")


def _known_domains_from_index(repo_root: str) -> set[str]:
    payload = _load_domain_index(repo_root)
    patterns = payload.get("patterns", {})
    domains: set[str] = set()
    if not isinstance(patterns, dict):
        return domains
    for pattern in patterns.keys():
        if not isinstance(pattern, str):
            continue
        host, _path = _split_domain_pattern(pattern)
        if isinstance(host, str) and host.startswith("*."):
            host = host[2:]
        normalized = _normalize_domain(host)
        if normalized and normalized not in {"*", "any"}:
            domains.add(normalized)
    return domains


def _known_domains(repo_root: str) -> list[str]:
    normalized_domains: set[str] = set()

    def _add_domain(value: Any) -> None:
        normalized = _normalize_domain(str(value or ""))
        if normalized:
            normalized_domains.add(normalized)

    _add_domain("solaceagi.com")
    _add_domain("www.google.com")
    for domain in _known_domains_from_index(repo_root):
        _add_domain(domain)
    for domain in _load_domain_profiles().keys():
        _add_domain(domain)
    for event in _load_domain_events():
        _add_domain(event.get("domain", ""))

    return sorted(normalized_domains, key=lambda item: (item != "solaceagi.com", item))


def _domain_setup_state(onboarding: dict[str, Any], status: dict[str, Any]) -> str:
    if onboarding.get("auth_state") != "logged_in":
        return "agent-only"
    if not bool(onboarding.get("apps_enabled", False)):
        return "pick-source"
    if bool(status.get("active", False)):
        return "active"
    if bool(status.get("requires_login", False)):
        return "login"
    if status.get("selected_apps"):
        return "ready"
    return "setup"


def _domain_descriptor(
    repo_root: str,
    domain: str,
    onboarding: Optional[dict[str, Any]] = None,
    *,
    include_app_counts: bool = False,
    status_override: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    normalized = _normalize_domain(domain)
    status = status_override if isinstance(status_override, dict) else _domain_status_payload(repo_root, normalized)
    current_onboarding = onboarding if isinstance(onboarding, dict) else _load_onboarding_state()
    available_app_count = 0
    if include_app_counts:
        apps_payload = _apps_for_domain(repo_root, normalized, "/", _load_account_tier())
        installed_apps = apps_payload.get("installed_apps", []) if isinstance(apps_payload, dict) else []
        store_apps = apps_payload.get("store_apps", []) if isinstance(apps_payload, dict) else []
        available_app_count = len(installed_apps) + len(store_apps)
    return {
        "id": normalized.replace(".", "-"),
        "host": normalized,
        "label": _domain_label_for_host(normalized),
        "url": f"http://127.0.0.1:{YINYANG_PORT}/domains/{urllib.parse.quote(normalized, safe='.')}",
        "icon": _domain_icon_for_host(normalized),
        "active": bool(status.get("active", False)),
        "requires_login": bool(status.get("requires_login", False)),
        "event_count": int(status.get("event_count", 0)),
        "selected_app_count": len(status.get("selected_apps", [])),
        "available_app_count": available_app_count,
        "setup_state": _domain_setup_state(current_onboarding, status),
        "selected_apps": list(status.get("selected_apps", [])),
        "keepalive_apps": list(status.get("keepalive_apps", [])),
    }


def _derive_onboarding_mode(
    auth_state: str,
    membership_tier: str,
    managed_llm_enabled: bool,
    model_sources: list[str],
    fallback: Optional[str],
) -> Optional[str]:
    if auth_state != "logged_in":
        return None
    primary = _primary_model_source(model_sources, managed_llm_enabled, fallback)
    if membership_tier != "free":
        return "paid"
    if primary == "managed":
        return "agent"
    if primary in {"byok", "cli"}:
        return primary
    if primary == "ollama":
        return "ollama"
    return "agent"


def _compute_apps_enabled(auth_state: str, membership_tier: str, managed_llm_enabled: bool, model_sources: list[str]) -> bool:
    if auth_state != "logged_in":
        return False
    normalized_sources = list(_normalize_model_sources(model_sources))
    if managed_llm_enabled and "managed" not in normalized_sources:
        normalized_sources.append("managed")
    if "ollama" in normalized_sources and not _ollama_config_payload()["configured"]:
        normalized_sources = [source for source in normalized_sources if source != "ollama"]
    return bool(normalized_sources)


def _load_onboarding_state() -> dict[str, Any]:
    try:
        raw = json.loads(ONBOARDING_PATH.read_text())
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        raw = {}
    if not isinstance(raw, dict):
        raw = {}
    legacy_tier = _legacy_account_tier_from_settings()
    auth_state = str(raw.get("auth_state", "")).strip().lower()
    if auth_state not in _AUTH_STATES:
        if bool(raw.get("completed")):
            auth_state = "logged_in"
        else:
            auth_state = "logged_out"
    membership_tier = _normalize_membership_tier(raw.get("membership_tier"), legacy_tier)
    model_sources = _normalize_model_sources(raw.get("model_sources"))
    legacy_model_source = _normalize_model_source(raw.get("model_source"))
    managed_llm_enabled = bool(raw.get("managed_llm_enabled", False))
    legacy_mode = str(raw.get("mode", "")).strip().lower()
    has_modern_contract = any(
        key in raw
        for key in ("auth_state", "membership_tier", "model_sources", "managed_llm_enabled", "device_id", "apps_enabled")
    )
    if legacy_model_source and legacy_model_source not in model_sources:
        model_sources.append(legacy_model_source)
    if auth_state == "logged_in" and not has_modern_contract:
        if legacy_mode == "paid":
            if membership_tier == "free":
                membership_tier = "starter"
            managed_llm_enabled = True if not raw.get("managed_llm_enabled") else managed_llm_enabled
            if "managed" not in model_sources:
                model_sources.append("managed")
        elif legacy_mode == "agent":
            managed_llm_enabled = True
            if "managed" not in model_sources:
                model_sources.append("managed")
        elif legacy_mode in {"byok", "cli"} and not model_sources:
            model_sources.append(legacy_mode)
    if managed_llm_enabled and "managed" not in model_sources:
        model_sources.append("managed")
    if legacy_model_source == "managed":
        managed_llm_enabled = True
    if auth_state != "logged_in":
        membership_tier = "free"
    if "ollama" in model_sources:
        ollama = _ollama_config_payload()
        if not ollama["configured"]:
            model_sources = [source for source in model_sources if source != "ollama"]
    model_source = _primary_model_source(model_sources, managed_llm_enabled, legacy_model_source)
    apps_enabled = _compute_apps_enabled(auth_state, membership_tier, managed_llm_enabled, model_sources)
    device_id = str(raw.get("device_id") or "").strip() or _default_device_id()
    state = {
        "auth_state": auth_state,
        "membership_tier": membership_tier,
        "managed_llm_enabled": managed_llm_enabled,
        "model_sources": model_sources,
        "model_source": model_source,
        "apps_enabled": apps_enabled,
        "device_id": device_id,
        "completed": auth_state == "logged_in",
        "mode": _derive_onboarding_mode(auth_state, membership_tier, managed_llm_enabled, model_sources, model_source),
        "membership_state": "paid" if membership_tier != "free" else "free",
    }
    return state


def _save_onboarding_state(payload: dict[str, Any]) -> dict[str, Any]:
    current = _load_onboarding_state()
    auth_state = str(payload.get("auth_state") or current["auth_state"]).strip().lower()
    if auth_state not in _AUTH_STATES:
        raise ValueError(f"auth_state must be one of {sorted(_AUTH_STATES)}")
    membership_tier = _normalize_membership_tier(payload.get("membership_tier"), current["membership_tier"])
    managed_llm_enabled = bool(payload.get("managed_llm_enabled", current["managed_llm_enabled"]))
    model_sources = list(current.get("model_sources", []))
    explicit_sources = payload.get("model_sources")
    if explicit_sources is not None:
        model_sources = _normalize_model_sources(explicit_sources)
        if "managed_llm_enabled" not in payload:
            managed_llm_enabled = "managed" in model_sources
    model_source = _normalize_model_source(payload.get("model_source"))
    if explicit_sources is None and model_source:
        model_sources = [model_source]
    elif model_source and model_source not in model_sources:
        model_sources.append(model_source)
    legacy_mode = str(payload.get("mode", "")).strip().lower()
    if legacy_mode in {"byok", "cli"}:
        model_sources = [legacy_mode]
        auth_state = "logged_in"
        membership_tier = "free"
        managed_llm_enabled = False
    elif legacy_mode == "agent":
        auth_state = "logged_in"
        membership_tier = "free"
        managed_llm_enabled = False
        model_sources = []
    elif legacy_mode == "paid":
        auth_state = "logged_in"
        membership_tier = membership_tier if membership_tier != "free" else "starter"
        managed_llm_enabled = True
        if "managed" not in model_sources:
            model_sources.append("managed")
    if auth_state == "logged_out":
        membership_tier = "free"
        managed_llm_enabled = False
        model_sources = []
    if managed_llm_enabled and "managed" not in model_sources:
        model_sources.append("managed")
    if not managed_llm_enabled:
        model_sources = [source for source in model_sources if source != "managed"]
    if membership_tier != "free" and not model_sources:
        model_sources = ["managed"]
        managed_llm_enabled = True
    device_id = str(payload.get("device_id") or current["device_id"]).strip() or _default_device_id()
    primary_source = _primary_model_source(model_sources, managed_llm_enabled, model_source)
    state = {
        "auth_state": auth_state,
        "membership_tier": membership_tier,
        "managed_llm_enabled": managed_llm_enabled,
        "model_sources": model_sources,
        "model_source": primary_source,
        "apps_enabled": _compute_apps_enabled(auth_state, membership_tier, managed_llm_enabled, model_sources),
        "device_id": device_id,
        "completed": auth_state == "logged_in",
        "mode": _derive_onboarding_mode(auth_state, membership_tier, managed_llm_enabled, model_sources, primary_source),
        "completed_ts": int(time.time()) if auth_state == "logged_in" else None,
    }
    ONBOARDING_PATH.parent.mkdir(parents=True, exist_ok=True)
    ONBOARDING_PATH.write_text(json.dumps(state, indent=2))
    return state


def _default_app_cron(app_id: str, site: str = "") -> str:
    normalized_site = _normalize_domain(site)
    if "morning-brief" in app_id:
        return "0 8 * * *"
    if any(token in app_id for token in ("search", "watch", "trend")) or normalized_site in {"google.com", "www.google.com", "news.google.com"}:
        return "0 */4 * * *"
    if "gmail" in app_id or normalized_site == "mail.google.com":
        return "0 9 * * 1-5"
    return "0 10 * * 1-5"


def _default_target_url(site: str) -> str:
    normalized_site = _normalize_domain(site)
    if not normalized_site:
        return "https://solaceagi.com/dashboard"
    return f"https://{normalized_site}/"


def _northstar_summary(repo_root: str, app_id: str) -> str:
    app_dir = _repo_app_dir(repo_root, app_id)
    if app_dir is None:
        return ""
    northstar_path = app_dir / "inbox" / "northstar.md"
    try:
        content = northstar_path.read_text(encoding="utf-8")
    except (FileNotFoundError, OSError):
        return ""
    for line in content.splitlines():
        stripped = line.strip().lstrip("#").strip()
        if stripped:
            return stripped[:240]
    return ""


def _default_app_config(repo_root: str, app_id: str) -> dict:
    manifest = _load_manifest_for_app(repo_root, app_id)
    session_rules = _load_session_rules_for_app(repo_root, app_id)
    site = str(manifest.get("site") or session_rules.get("site") or "")
    description = str(manifest.get("description") or session_rules.get("description") or "")
    northstar = _northstar_summary(repo_root, app_id)
    report_name = "latest.html" if bool(manifest.get("custom", False)) else ""
    keep_alive = session_rules.get("keep_alive", {})
    interval = keep_alive.get("interval_minutes", 15) if isinstance(keep_alive, dict) else 15
    try:
        keepalive_minutes = int(interval)
    except (TypeError, ValueError):
        keepalive_minutes = 15
    keepalive_minutes = max(1, min(1440, keepalive_minutes))
    return {
        "objective": northstar or description or f"Run {app_id.replace('-', ' ')} and produce a useful local report.",
        "target_url": str(session_rules.get("check_url") or session_rules.get("login_url") or _default_target_url(site)),
        "cron": _default_app_cron(app_id, site),
        "keepalive_minutes": keepalive_minutes,
        "report_name": report_name,
    }


def _load_app_config(repo_root: str, app_id: str) -> dict:
    defaults = _default_app_config(repo_root, app_id)
    settings = _load_settings()
    raw_configs = settings.get("app_configs", {})
    if not isinstance(raw_configs, dict):
        return defaults
    raw = raw_configs.get(app_id, {})
    if not isinstance(raw, dict):
        return defaults
    merged = dict(defaults)
    for key in ("objective", "target_url", "cron", "report_name"):
        value = raw.get(key)
        if isinstance(value, str) and value.strip():
            merged[key] = value.strip()
    keepalive = raw.get("keepalive_minutes")
    if isinstance(keepalive, int):
        merged["keepalive_minutes"] = max(1, min(1440, keepalive))
    return merged


def _save_app_config(repo_root: str, app_id: str, payload: dict) -> dict:
    if not isinstance(payload, dict):
        raise ValueError("invalid config payload")
    current = _load_app_config(repo_root, app_id)
    objective = str(payload.get("objective", current["objective"])).strip()
    if not objective or len(objective) > 4000:
        raise ValueError("objective must be 1-4000 chars")
    target_url = str(payload.get("target_url", current["target_url"])).strip()
    if not target_url or len(target_url) > 2048:
        raise ValueError("target_url must be 1-2048 chars")
    cron = str(payload.get("cron", current["cron"])).strip()
    if len(cron) > 64 or len(cron.split()) != 5:
        raise ValueError("cron must be a 5-field expression <= 64 chars")
    keepalive_raw = payload.get("keepalive_minutes", current["keepalive_minutes"])
    try:
        keepalive_minutes = int(keepalive_raw)
    except (TypeError, ValueError):
        raise ValueError("keepalive_minutes must be an integer")
    keepalive_minutes = max(1, min(1440, keepalive_minutes))
    report_name = str(payload.get("report_name", current.get("report_name", ""))).strip()[:128]

    merged = {
        "objective": objective,
        "target_url": target_url,
        "cron": cron,
        "keepalive_minutes": keepalive_minutes,
        "report_name": report_name,
    }
    settings = _load_settings()
    app_configs = settings.get("app_configs", {})
    if not isinstance(app_configs, dict):
        app_configs = {}
    app_configs[app_id] = merged
    settings["app_configs"] = app_configs
    _save_settings(settings)
    return merged


def _delete_app_config(app_id: str) -> None:
    settings = _load_settings()
    app_configs = settings.get("app_configs", {})
    if not isinstance(app_configs, dict):
        return
    if app_id not in app_configs:
        return
    app_configs.pop(app_id, None)
    settings["app_configs"] = app_configs
    _save_settings(settings)


def _delete_schedules_for_app(app_id: str) -> int:
    with _SCHEDULES_LOCK:
        schedules = load_schedules()
        kept = [schedule for schedule in schedules if schedule.get("app_id") != app_id]
        removed = len(schedules) - len(kept)
        if removed:
            save_schedules(kept)
    return removed


def _delete_custom_app(repo_root: str, app_id: str) -> dict:
    app_dir = _local_app_dir(repo_root, app_id)
    if app_dir is None or not app_dir.is_dir():
        raise FileNotFoundError("custom app not found")
    shutil.rmtree(app_dir)
    _set_app_installed(repo_root, app_id, False)
    _delete_app_config(app_id)
    removed_schedules = _delete_schedules_for_app(app_id)
    _rebuild_domain_index(repo_root)
    return {
        "app_id": app_id,
        "removed_path": str(app_dir),
        "removed_schedules": removed_schedules,
    }


def _normalize_cloud_twin_url(url: str) -> str:
    candidate = url.strip()
    if not candidate:
        raise ValueError("cloud twin url is required")
    parsed = urllib.parse.urlparse(candidate)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("cloud twin url must start with http:// or https://")
    if not parsed.hostname:
        raise ValueError("cloud twin url must include a hostname")
    if parsed.username or parsed.password:
        raise ValueError("cloud twin url must not include embedded credentials")
    if parsed.query or parsed.fragment:
        raise ValueError("cloud twin url must not include query or fragment")
    clean_path = parsed.path.rstrip("/")
    return urllib.parse.urlunparse((parsed.scheme, parsed.netloc, clean_path, "", "", ""))


def _ping_cloud_twin(url: str, timeout: float = 5.0) -> dict:
    if not url:
        return {"reachable": False, "latency_ms": None}
    started = time.perf_counter()
    request = urllib.request.Request(f"{url}/health", method="GET")
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            response.read(64 * 1024)
    except urllib.error.URLError:
        return {"reachable": False, "latency_ms": None}
    except OSError:
        return {"reachable": False, "latency_ms": None}
    latency_ms = int((time.perf_counter() - started) * 1000)
    return {"reachable": True, "latency_ms": latency_ms}


def _cloud_twin_status_payload() -> dict:
    settings = _load_settings()
    cloud_twin = _normalized_cloud_twin_settings(settings.get("cloud_twin", {}))
    url = cloud_twin["url"]
    ping = _ping_cloud_twin(url) if url else {"reachable": False, "latency_ms": None}
    return {
        "configured": bool(url),
        "url": url,
        "reachable": ping["reachable"],
        "last_ping_ms": ping["latency_ms"],
    }


def _cloud_twin_mode_enabled(cloud_twin: bool = False) -> bool:
    env_value = os.environ.get("SOLACE_CLOUD_TWIN", "").strip().lower()
    return cloud_twin or env_value in {"1", "true", "yes", "on"}


def _hub_integration_enabled(cloud_twin: bool = False) -> bool:
    return not _cloud_twin_mode_enabled(cloud_twin)


def _cloud_twin_display() -> str:
    return os.environ.get("DISPLAY", CLOUD_TWIN_DISPLAY)


def _health_payload(app_count: int, port: int, cloud_twin_mode: bool) -> dict:
    return {
        "status": "ok",
        "apps": app_count,
        "version": _SERVER_VERSION,
        "evidence_count": count_evidence(),
        "schedule_count": len(load_schedules()),
        "uptime_seconds": int(time.time() - _SERVER_START_TIME),
        "port": port,
        "mode": "cloud_twin" if cloud_twin_mode else "local",
        "display": _cloud_twin_display() if cloud_twin_mode else "",
    }


def _launch_chrome_cloud_twin(url: str) -> subprocess.Popen:
    browser = os.environ.get("SOLACE_BROWSER", "")
    if not browser:
        browser = shutil.which("chromium-browser") or shutil.which("chromium") or "chromium-browser"
    env = dict(os.environ)
    env["DISPLAY"] = _cloud_twin_display()
    return subprocess.Popen(
        [
            browser,
            f"--display={env['DISPLAY']}",
            "--no-sandbox",
            "--disable-dev-shm-usage",
            url,
        ],
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        env=env,
    )


def _forward_cloud_twin_session(cloud_twin_url: str, payload: dict, timeout: float = 10.0) -> dict:
    body = json.dumps(payload).encode()
    request = urllib.request.Request(
        f"{cloud_twin_url}/api/v1/sessions",
        data=body,
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    started = time.perf_counter()
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            response_body = response.read().decode()
            data = json.loads(response_body)
            latency_ms = int((time.perf_counter() - started) * 1000)
            return {
                "ok": True,
                "status": response.status,
                "data": data if isinstance(data, dict) else {},
                "latency_ms": latency_ms,
            }
    except urllib.error.HTTPError as exc:
        try:
            error_data = json.loads(exc.read().decode())
        except json.JSONDecodeError:
            error_data = {"error": f"cloud twin returned HTTP {exc.code}"}
        return {"ok": False, "status": exc.code, "data": error_data, "latency_ms": None}
    except urllib.error.URLError:
        return {"ok": False, "status": 503, "data": {"error": "cloud twin unreachable"}, "latency_ms": None}
    except json.JSONDecodeError:
        return {"ok": False, "status": 502, "data": {"error": "cloud twin returned invalid JSON"}, "latency_ms": None}
    except OSError:
        return {"ok": False, "status": 503, "data": {"error": "cloud twin unreachable"}, "latency_ms": None}


def _cloud_tunnel_worker(api_key: str, yinyang_bearer: str, yinyang_port: int) -> None:
    global _CLOUD_TUNNEL_ACTIVE, _CLOUD_TUNNEL_CLIENT, _CLOUD_TUNNEL_LOOP
    loop = asyncio.new_event_loop()
    client = HubTunnelClient(api_key, yinyang_bearer, yinyang_port=yinyang_port)
    with _CLOUD_TUNNEL_LOCK:
        _CLOUD_TUNNEL_CLIENT = client
        _CLOUD_TUNNEL_LOOP = loop
        _CLOUD_TUNNEL_ACTIVE = True
    asyncio.set_event_loop(loop)
    try:
        loop.run_until_complete(client.run())
    finally:
        with _CLOUD_TUNNEL_LOCK:
            _CLOUD_TUNNEL_ACTIVE = False
            _CLOUD_TUNNEL_LOOP = None
        loop.close()


def _launch_cloud_tunnel(api_key: str, yinyang_bearer: str, yinyang_port: int) -> None:
    global _CLOUD_TUNNEL_ACTIVE, _CLOUD_TUNNEL_THREAD
    with _CLOUD_TUNNEL_LOCK:
        if _CLOUD_TUNNEL_THREAD is not None and _CLOUD_TUNNEL_THREAD.is_alive() and _CLOUD_TUNNEL_ACTIVE:
            return
        _CLOUD_TUNNEL_ACTIVE = True
        _CLOUD_TUNNEL_THREAD = threading.Thread(
            target=_cloud_tunnel_worker,
            args=(api_key, yinyang_bearer, yinyang_port),
            daemon=True,
        )
        thread = _CLOUD_TUNNEL_THREAD
    thread.start()


def _stop_cloud_tunnel() -> None:
    global _CLOUD_TUNNEL_ACTIVE, _CLOUD_TUNNEL_CLIENT, _CLOUD_TUNNEL_LOOP, _CLOUD_TUNNEL_THREAD
    with _CLOUD_TUNNEL_LOCK:
        client = _CLOUD_TUNNEL_CLIENT
        loop = _CLOUD_TUNNEL_LOOP
        thread = _CLOUD_TUNNEL_THREAD
        _CLOUD_TUNNEL_ACTIVE = False
    if client is not None and loop is not None and loop.is_running():
        asyncio.run_coroutine_threadsafe(client.stop(), loop)
    if thread is not None and thread.is_alive():
        thread.join(timeout=2)
    with _CLOUD_TUNNEL_LOCK:
        _CLOUD_TUNNEL_THREAD = None
        _CLOUD_TUNNEL_LOOP = None


def _cloud_tunnel_status_payload() -> dict:
    with _CLOUD_TUNNEL_LOCK:
        retries = _CLOUD_TUNNEL_CLIENT.retries if _CLOUD_TUNNEL_CLIENT is not None else 0
        active = _CLOUD_TUNNEL_ACTIVE
    return {
        "active": active,
        "relay": SOLACEAGI_RELAY_URL if active else None,
        "retries": retries,
    }


def load_evidence(limit: int = 50, offset: int = 0) -> list[dict]:
    """Load evidence records from JSONL file. Returns list in reverse-chronological order."""
    try:
        lines = EVIDENCE_PATH.read_text().splitlines()
    except FileNotFoundError:
        return []
    records = []
    for line in lines:
        line = line.strip()
        if not line:
            continue
        try:
            records.append(json.loads(line))
        except json.JSONDecodeError:
            continue
    # Reverse chronological, then paginate
    records.reverse()
    return records[offset: offset + limit]


def count_evidence() -> int:
    """Count total evidence records."""
    try:
        return sum(1 for ln in EVIDENCE_PATH.read_text().splitlines() if ln.strip())
    except FileNotFoundError:
        return 0


# ---------------------------------------------------------------------------
# Notification storage — Task 020
# ---------------------------------------------------------------------------
def _load_notifications_raw() -> list:
    """Load notifications from ~/.solace/notifications.json. Returns list."""
    if not NOTIFICATIONS_PATH.exists():
        return []
    try:
        data = json.loads(NOTIFICATIONS_PATH.read_text())
        return data if isinstance(data, list) else []
    except json.JSONDecodeError:
        return []


def _append_notification(category: str, title: str, body: str, level: str = "info") -> None:
    """Append a notification to the store. Thread-safe."""
    if category not in NOTIF_CATEGORIES:
        category = "info"
    notif = {
        "id": str(uuid.uuid4()),
        "category": category,
        "title": title[:128],
        "body": body[:512],
        "level": level,  # info | warn | error
        "timestamp": int(time.time()),
        "read": False,
    }
    with _NOTIF_LOCK:
        notifs = _load_notifications_raw()
        notifs.append(notif)
        if len(notifs) > MAX_NOTIFICATIONS:
            notifs = notifs[-MAX_NOTIFICATIONS:]
        NOTIFICATIONS_PATH.parent.mkdir(parents=True, exist_ok=True)
        NOTIFICATIONS_PATH.write_text(json.dumps(notifs, indent=2))


def _yinyang_now_iso() -> str:
    """Return current UTC timestamp in ISO-8601 Zulu format."""
    return datetime.now(timezone.utc).isoformat(timespec="microseconds").replace("+00:00", "Z")


def _yinyang_notification_public(notif: dict[str, Any]) -> dict[str, Any]:
    """Return the public notification payload without internal-only fields."""
    return {
        "id": str(notif.get("id", "")),
        "type": str(notif.get("type", "")),
        "message": str(notif.get("message", "")),
        "priority": str(notif.get("priority", "normal")),
        "read": bool(notif.get("read", False)),
        "ts": str(notif.get("ts", "")),
        "agent_id": notif.get("agent_id"),
        "run_id": notif.get("run_id"),
        "actions": list(notif.get("actions", [])),
        "metadata": dict(notif.get("metadata", {})),
    }


def _yinyang_sse_frame(notif: dict[str, Any]) -> str:
    """Encode one notification as a server-sent event frame."""
    public_notif = _yinyang_notification_public(notif)
    return f"id: {public_notif['id']}\ndata: {json.dumps(public_notif)}\n\n"


def _create_yinyang_notification(
    type_: str,
    message: str,
    priority: str,
    agent_id: Optional[str] = None,
    run_id: Optional[str] = None,
    actions: Optional[list[dict[str, Any]]] = None,
    metadata: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    """Create and broadcast one in-memory yinyang notification."""
    global _YINYANG_NOTIF_COUNTER

    notif = {
        "id": f"notif_{secrets.token_hex(8)}",
        "type": type_,
        "message": message,
        "priority": priority,
        "read": False,
        "ts": _yinyang_now_iso(),
        "agent_id": agent_id,
        "run_id": run_id,
        "actions": list(actions or []),
        "metadata": dict(metadata or {}),
    }
    with _YINYANG_NOTIF_LOCK:
        _YINYANG_NOTIF_COUNTER += 1
        notif["seq"] = _YINYANG_NOTIF_COUNTER
        _YINYANG_NOTIFICATIONS.append(notif)

    frame = _yinyang_sse_frame(notif)
    with _YINYANG_SSE_CLIENTS_LOCK:
        for client_queue in _YINYANG_SSE_CLIENTS:
            try:
                client_queue.put_nowait(frame)
            except queue.Full:
                pass

    return notif


def _yinyang_sse_token_valid(expected_sha256: str, token: str) -> bool:
    """Validate EventSource query token against the configured SHA-256 bearer value."""
    return bool(expected_sha256 and _SHA256_HEX_RE.fullmatch(token) and token == expected_sha256)


