def _invalid_custom_app_name(name: str) -> bool:
    return ".." in name or "/" in name or "\\" in name


def _slugify_custom_app_name(name: str) -> str:
    return re.sub(r"[^a-z0-9]+", "-", name.strip().lower()).strip("-")[:50].strip("-")


def _custom_app_manifest(app_id: str, display_name: str, description: str, domain: str) -> str:
    return (
        f"id: {app_id}\n"
        f"name: {json.dumps(display_name)}\n"
        f"description: {json.dumps(description)}\n"
        'category: "custom"\n'
        'status: "installed"\n'
        'safety: "B"\n'
        'tier: "free"\n'
        'domains:\n'
        f'  - {json.dumps(domain)}\n'
        f"site: {domain}\n"
        'type: "custom"\n'
        'custom: true\n'
        'local_only: true\n'
    )


def _custom_app_session_rules(app_id: str, display_name: str, description: str, domain: str) -> str:
    app_url = f"https://{domain}/"
    return (
        f"app: {app_id}\n"
        f"display_name: {json.dumps(display_name)}\n"
        'version: "1.0.0"\n'
        'category: "custom"\n'
        f"site: {domain}\n"
        f"login_url: {json.dumps(app_url)}\n"
        f"check_url: {json.dumps(app_url)}\n"
        'success_signals:\n'
        '  - "TODO: add success signal"\n'
        'failure_signals:\n'
        '  - "TODO: add failure signal"\n'
        'keep_alive:\n'
        '  interval_minutes: 15\n'
        '  action: "navigate"\n'
        f"  url: {json.dumps(app_url)}\n"
        'tier_required: "free"\n'
        'evidence_on_check: true\n'
        f"description: {json.dumps(description)}\n"
    )


def _create_custom_app_scaffold(repo_root: str, raw_domain: str, raw_name: str, raw_description: str) -> dict:
    domain = _normalize_domain(raw_domain)
    name = raw_name.strip()
    description = raw_description.strip()
    if not domain:
        raise ValueError("domain required")
    if not name or _invalid_custom_app_name(name):
        raise ValueError("invalid app name")
    app_id = _slugify_custom_app_name(name)
    if not app_id:
        raise ValueError("invalid app name")

    app_dir = _local_apps_root_path() / domain / app_id
    if app_dir.exists():
        raise FileExistsError("app already exists")

    manifest_text = _custom_app_manifest(app_id, name, description or f"Custom app for {domain}", domain)
    session_rules_text = _custom_app_session_rules(app_id, name, description or f"Custom app for {domain}", domain)
    app_dir.mkdir(parents=True, exist_ok=False)
    (app_dir / "manifest.yaml").write_text(manifest_text)
    (app_dir / "session-rules.yaml").write_text(session_rules_text)
    _rebuild_domain_index(repo_root)

    relative_app_path = Path("apps") / domain / app_id
    return {
        "app_id": app_id,
        "path": f"{relative_app_path.as_posix()}/",
        "manifest_path": (relative_app_path / "manifest.yaml").as_posix(),
        "session_rules_path": (relative_app_path / "session-rules.yaml").as_posix(),
        "manifest_template": manifest_text,
        "session_rules_template": session_rules_text,
    }


def _custom_apps_sync_bundle(repo_root: str) -> list[dict]:
    bundle: list[dict] = []
    for app_id, manifest, manifest_path in _iter_local_manifest_records(repo_root):
        if not bool(manifest.get("custom", False)):
            continue
        app_dir = manifest_path.parent
        session_rules_path = app_dir / "session-rules.yaml"
        try:
            manifest_yaml = manifest_path.read_text()
            session_rules_yaml = session_rules_path.read_text()
        except FileNotFoundError:
            continue
        except OSError:
            continue
        bundle.append({
            "app_id": app_id,
            "manifest_yaml": manifest_yaml,
            "session_rules_yaml": session_rules_yaml,
        })
    return bundle


def _check_session(rule: dict) -> str:
    """Return session status without browser automation for this task."""
    return "unknown"


def _record_session_status(rule: dict, status: str, checked_at: int) -> dict:
    """Update the status cache for one app and return the cached entry."""
    app_id = str(rule.get("app", ""))
    entry = {
        "app": app_id,
        "status": status,
        "last_check": checked_at,
        "next_check": checked_at + _session_interval_seconds(rule),
    }
    with _SESSION_STATUS_LOCK:
        _SESSION_STATUS[app_id] = entry
    return entry


def _run_session_check(rule: dict) -> dict:
    """Check one session rule, record evidence, and update cached status."""
    checked_at = int(time.time())
    status = _check_session(rule)
    status_entry = _record_session_status(rule, status, checked_at)
    record_evidence(
        "session_check",
        {
            "app": rule.get("app", ""),
            "status": status,
            "check_url": rule.get("check_url", ""),
        },
    )
    return status_entry


def time_since_last_check(app_id: str) -> int:
    """Return seconds since the last check, or a large number if never checked."""
    with _SESSION_STATUS_LOCK:
        status_entry = _SESSION_STATUS.get(app_id, {})
    last_check = status_entry.get("last_check")
    if not isinstance(last_check, int):
        return 10**9
    return max(0, int(time.time()) - last_check)


def _session_keepalive_loop() -> None:
    """Check due session rules on a daemon thread and record evidence."""
    while not _SESSION_KEEPALIVE_STOP.is_set():
        for rule in _get_session_rules_snapshot():
            app_id = str(rule.get("app", ""))
            if not app_id:
                continue
            if time_since_last_check(app_id) >= _session_interval_seconds(rule):
                _run_session_check(rule)
        _SESSION_KEEPALIVE_STOP.wait(60)


def _start_session_keepalive_thread() -> None:
    """Start the keep-alive daemon thread once per process."""
    global _SESSION_KEEPALIVE_THREAD
    if _SESSION_KEEPALIVE_THREAD is not None and _SESSION_KEEPALIVE_THREAD.is_alive():
        return
    _SESSION_KEEPALIVE_STOP.clear()
    _SESSION_KEEPALIVE_THREAD = threading.Thread(
        target=_session_keepalive_loop,
        name="session-keepalive",
        daemon=True,
    )
    _SESSION_KEEPALIVE_THREAD.start()


# ---------------------------------------------------------------------------
# Health check helpers — Task 023
# ---------------------------------------------------------------------------
def _run_single_health_check(check_id: str) -> dict:
    """Run one named health check and return result dict. Never raises."""
    now_ts = time.time()
    passed = False
    detail = ""
    if check_id == "server":
        passed = True
        detail = "server is responding"
    elif check_id == "oauth3":
        try:
            _ = OAUTH3_TOKENS_PATH.parent.exists()
            passed = True
            detail = "token store directory accessible"
        except OSError as exc:
            detail = str(exc)
    elif check_id == "recipes":
        try:
            passed = RECIPES_DIR.is_dir()
            detail = "recipe dir found" if passed else "recipe dir missing"
        except OSError as exc:
            detail = str(exc)
    elif check_id == "twin":
        passed = True
        detail = "twin queue accessible"
    elif check_id == "budget":
        try:
            _ = BUDGET_PATH.parent.exists()
            passed = True
            detail = "budget store directory accessible"
        except OSError as exc:
            detail = str(exc)
    return {
        "check_id": check_id,
        "passed": passed,
        "detail": detail,
        "checked_at": _utc_isoformat(now_ts),
    }


def _run_all_health_checks() -> list[dict]:
    """Run all named health checks and return list of results."""
    return [_run_single_health_check(c["check_id"]) for c in HEALTH_CHECKS]


def _build_full_health_snapshot() -> dict:
    """Run all checks, compute overall status, append to history, return snapshot."""
    results = _run_all_health_checks()
    all_pass = all(r["passed"] for r in results)
    overall = "healthy" if all_pass else "degraded"
    uptime = int(time.time() - _SERVER_START_TIME)
    if _HAS_PSUTIL:
        cpu_pct = _psutil.cpu_percent(interval=None)
        mem_mb = _psutil.virtual_memory().used / 1024 / 1024
    else:
        cpu_pct = 0.0
        mem_mb = 0.0
    with _METRICS_LOCK:
        req_count = sum(_REQUEST_COUNTS.values())
    snapshot = {
        "status": overall,
        "uptime_s": uptime,
        "cpu_pct": cpu_pct,
        "mem_mb": round(mem_mb, 2),
        "req_count": req_count,
        "checks": results,
        "timestamp": _utc_isoformat(time.time()),
    }
    with _HEALTH_LOCK:
        _HEALTH_HISTORY.append(snapshot)
        if len(_HEALTH_HISTORY) > 100:
            _HEALTH_HISTORY.pop(0)
    return snapshot


# ---------------------------------------------------------------------------
# HTTP Handler — theorem: every route returns JSON, every error is specific.
# ---------------------------------------------------------------------------
def _parse_ts(ts_str: str) -> float:
    """Parse ISO8601 UTC string to epoch float. Returns 0.0 on failure."""
    try:
        dt = datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
        return dt.timestamp()
    except (ValueError, AttributeError):
        return 0.0


class YinyangHandler(http.server.BaseHTTPRequestHandler):
    def _cors_origin(self) -> str:
        server_port = int(getattr(self.server, "server_port", YINYANG_PORT))
        allowed = {
            f"http://localhost:{YINYANG_PORT}",
            f"http://127.0.0.1:{YINYANG_PORT}",
            f"http://localhost:{server_port}",
            f"http://127.0.0.1:{server_port}",
            "tauri://localhost",
            "http://tauri.localhost",
            "app://localhost",
            "null",
        }
        origin = self.headers.get("Origin", "").strip()
        if origin in allowed:
            return origin
        return f"http://localhost:{YINYANG_PORT}"

    def _send_cors_headers(self) -> None:
        self.send_header("Access-Control-Allow-Origin", self._cors_origin())
        self.send_header("Vary", "Origin")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, PATCH, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Authorization, Content-Type")

    def do_OPTIONS(self) -> None:
        self.send_response(204)
        self._send_cors_headers()
        self.send_header("Content-Length", "0")
        self.end_headers()

    def _check_auth(self) -> bool:
        """Return True if authorized, False after sending 401."""
        sha256_value = getattr(self.server, "session_token_sha256", "")
        if not sha256_value:
            return True
        auth_header = self.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            self._send_json({"error": "unauthorized"}, 401)
            return False
        provided = auth_header[len("Bearer "):]
        if not _SHA256_HEX_RE.fullmatch(provided):
            self._send_json({"error": "unauthorized"}, 401)
            return False
        if provided != sha256_value:
            self._send_json({"error": "unauthorized"}, 401)
            return False
        return True

    def _require_auth(self) -> bool:
        return self._check_auth()

    def _send_json_compat(self, status: int, body: dict[str, Any]) -> None:
        param_names = list(inspect.signature(self._send_json).parameters)
        if len(param_names) >= 2 and param_names[0] in {"code", "status", "response_code"}:
            self._send_json(status, body)
            return
        self._send_json(body, status)

    def _tracker_body(self, payload: Optional[dict[str, Any]] = None) -> Optional[dict[str, Any]]:
        body = payload if payload is not None else self._read_json_body()
        if body is None:
            return None
        if not isinstance(body, dict):
            self._send_json_compat(400, {"error": "body must be a JSON object"})
            return None
        return body

    def _compat_browser_state(self) -> dict[str, Any]:
        with _COMPAT_BROWSER_LOCK:
            return {
                "current_url": _COMPAT_BROWSER_STATE.get("current_url", "https://solaceagi.com/dashboard"),
                "last_action": _COMPAT_BROWSER_STATE.get("last_action"),
                "actions": list(_COMPAT_BROWSER_STATE.get("actions", [])),
            }

    def _update_compat_browser_state(self, action: dict[str, Any]) -> dict[str, Any]:
        with _COMPAT_BROWSER_LOCK:
            _COMPAT_BROWSER_STATE["last_action"] = action
            actions = _COMPAT_BROWSER_STATE.setdefault("actions", [])
            actions.append(action)
            if len(actions) > 50:
                del actions[:-50]
            if action.get("url"):
                _COMPAT_BROWSER_STATE["current_url"] = action["url"]
            return {
                "current_url": _COMPAT_BROWSER_STATE.get("current_url", "https://solaceagi.com/dashboard"),
                "last_action": _COMPAT_BROWSER_STATE.get("last_action"),
                "actions": list(_COMPAT_BROWSER_STATE.get("actions", [])),
            }

    def _local_apps_root(self) -> Optional[Path]:
        root = _local_apps_root_path()
        root.mkdir(parents=True, exist_ok=True)
        return root

    def _resolve_app_root(self, app_id: str) -> Optional[Path]:
        repo_root = str(Path(getattr(self.server, "repo_root", Path(__file__).parent)).resolve())
        return _repo_app_dir(repo_root, app_id)

    def _list_known_apps(self) -> list[str]:
        repo_root = str(Path(getattr(self.server, "repo_root", Path(__file__).parent)).resolve())
        return load_apps(repo_root)

    def _find_browser_window_id(self) -> Optional[str]:
        try:
            result = subprocess.run(
                ["xwininfo", "-root", "-tree"],
                capture_output=True,
                check=False,
                text=True,
                timeout=5,
            )
        except (OSError, subprocess.TimeoutExpired):
            return None
        if result.returncode != 0:
            return None
        patterns = [
            re.compile(r'^\s*(0x[0-9a-f]+)\s+"[^"]* - Solace"', re.MULTILINE),
            re.compile(r'^\s*(0x[0-9a-f]+)\s+"[^"]*Chromium[^"]*"', re.MULTILINE),
        ]
        for pattern in patterns:
            match = pattern.search(result.stdout)
            if match:
                return match.group(1)
        return None

    def _capture_browser_window_artifact(self, filename: str) -> Optional[dict[str, Any]]:
        window_id = self._find_browser_window_id()
        if not window_id:
            return None
        artifacts_dir = Path.home() / ".solace" / "artifacts"
        artifacts_dir.mkdir(parents=True, exist_ok=True)
        target = artifacts_dir / filename
        try:
            result = subprocess.run(
                ["import", "-window", window_id, str(target)],
                capture_output=True,
                check=False,
                timeout=10,
            )
        except (OSError, subprocess.TimeoutExpired):
            return None
        if result.returncode != 0 or not target.exists():
            return None
        return {
            "window_id": window_id,
            "filepath": str(target),
            "filename": target.name,
            "size_bytes": target.stat().st_size,
        }

    def _list_hub_windows(self) -> list[dict[str, Any]]:
        if not shutil.which("xwininfo"):
            return []
        try:
            result = subprocess.run(
                ["xwininfo", "-root", "-tree"],
                capture_output=True,
                text=True,
                timeout=10,
                check=False,
            )
        except (OSError, subprocess.TimeoutExpired):
            return []
        if result.returncode != 0:
            return []
        windows: list[dict[str, Any]] = []
        pattern = re.compile(
            r'^\s*(0x[0-9a-f]+)\s+"([^"]+)".*?(\d+)x(\d+)\+(-?\d+)\+(-?\d+)'
        )
        for line in result.stdout.splitlines():
            match = pattern.search(line)
            if not match:
                continue
            title = match.group(2)
            if title != "Solace Hub":
                continue
            window_id = match.group(1)
            pid: Optional[int] = None
            if shutil.which("xprop"):
                try:
                    xprop_result = subprocess.run(
                        ["xprop", "-id", window_id, "_NET_WM_PID"],
                        capture_output=True,
                        text=True,
                        timeout=5,
                        check=False,
                    )
                    pid_match = re.search(r"=\s*(\d+)", xprop_result.stdout)
                    if pid_match:
                        pid = int(pid_match.group(1))
                except (OSError, subprocess.TimeoutExpired, ValueError):
                    pid = None
            windows.append(
                {
                    "window_id": window_id,
                    "title": title,
                    "width": int(match.group(3)),
                    "height": int(match.group(4)),
                    "x": int(match.group(5)),
                    "y": int(match.group(6)),
                    "pid": pid,
                }
            )
        return windows

    def _find_hub_window_id(self) -> Optional[str]:
        windows = self._list_hub_windows()
        if not windows:
            return None
        return windows[0]["window_id"]

    def _capture_hub_window_artifact(self, filename: str) -> Optional[dict[str, Any]]:
        window_id = self._find_hub_window_id()
        if not window_id:
            return None
        artifacts_dir = Path.home() / ".solace" / "artifacts"
        artifacts_dir.mkdir(parents=True, exist_ok=True)
        target = artifacts_dir / filename
        try:
            result = subprocess.run(
                ["import", "-window", window_id, str(target)],
                capture_output=True,
                check=False,
                timeout=10,
            )
        except (OSError, subprocess.TimeoutExpired):
            return None
        if result.returncode != 0 or not target.exists():
            return None
        return {
            "window_id": window_id,
            "filepath": str(target),
            "filename": target.name,
            "size_bytes": target.stat().st_size,
        }

    def _hub_accessibility_root(self) -> Optional[Any]:
        try:
            import pyatspi  # type: ignore
        except Exception:
            return None
        try:
            desktop = pyatspi.Registry.getDesktop(0)
        except Exception:
            return None
        for i in range(desktop.childCount):
            app = desktop.getChildAtIndex(i)
            if getattr(app, "name", None) != "solace-hub":
                continue
            return app
        return None

    def _hub_accessibility_snapshot(
        self,
        node: Any,
        *,
        depth: int = 0,
        max_depth: int = 4,
        max_children: int = 20,
    ) -> dict[str, Any]:
        role_name = ""
        try:
            role_name = node.getRoleName()
        except Exception:
            role_name = ""
        snapshot: dict[str, Any] = {
            "name": getattr(node, "name", "") or "",
            "role": role_name,
            "child_count": int(getattr(node, "childCount", 0) or 0),
        }
        if depth >= max_depth:
            return snapshot
        children: list[dict[str, Any]] = []
        child_count = int(getattr(node, "childCount", 0) or 0)
        for idx in range(min(child_count, max_children)):
            try:
                child = node.getChildAtIndex(idx)
            except Exception:
                continue
            children.append(
                self._hub_accessibility_snapshot(
                    child,
                    depth=depth + 1,
                    max_depth=max_depth,
                    max_children=max_children,
                )
            )
        if children:
            snapshot["children"] = children
        return snapshot

    def _hub_find_accessible(
        self,
        node: Any,
        *,
        name: str,
        role: Optional[str] = None,
        max_depth: int = 8,
        depth: int = 0,
    ) -> Optional[Any]:
        node_name = (getattr(node, "name", "") or "").strip()
        node_role = ""
        try:
            node_role = node.getRoleName()
        except Exception:
            node_role = ""
        if node_name == name and (role is None or node_role == role):
            return node
        if depth >= max_depth:
            return None
        child_count = int(getattr(node, "childCount", 0) or 0)
        for idx in range(child_count):
            try:
                child = node.getChildAtIndex(idx)
            except Exception:
                continue
            found = self._hub_find_accessible(
                child,
                name=name,
                role=role,
                max_depth=max_depth,
                depth=depth + 1,
            )
            if found is not None:
                return found
        return None

    def _hub_invoke_action(
        self,
        *,
        name: str,
        action_name: str = "click",
        role: Optional[str] = None,
    ) -> dict[str, Any]:
        root = self._hub_accessibility_root()
        if root is None:
            return {
                "status": "unavailable",
                "error": "hub_accessibility_unavailable",
            }
        target = self._hub_find_accessible(root, name=name, role=role)
        if target is None:
            return {
                "status": "not_found",
                "error": "hub_accessible_not_found",
                "name": name,
                "role": role,
            }
        try:
            action_iface = target.queryAction()
        except Exception:
            return {
                "status": "unsupported",
                "error": "hub_action_not_supported",
                "name": name,
                "role": role,
            }
        chosen_index: Optional[int] = None
        chosen_name = action_name
        for idx in range(action_iface.nActions):
            candidate = action_iface.getName(idx)
            if candidate == action_name:
                chosen_index = idx
                break
        if chosen_index is None and action_name == "click":
            for idx in range(action_iface.nActions):
                candidate = action_iface.getName(idx)
                if candidate in {"press", "click", "activate"}:
                    chosen_index = idx
                    chosen_name = candidate
                    break
        if chosen_index is None:
            return {
                "status": "unsupported",
                "error": "hub_action_not_supported",
                "name": name,
                "role": role,
                "action": action_name,
            }
        result = bool(action_iface.doAction(chosen_index))
        return {
            "status": "ok" if result else "failed",
            "name": name,
            "role": role,
            "action": chosen_name,
        }

    def _reject_extension_era_route(self, path: str) -> bool:
        blocked_prefixes = (
            "/api/v1/extension-store",
            "/api/v1/extension-conflicts",
            "/api/v1/ext-firewall",
            "/web/extension-store",
            "/web/extension-conflict-detector",
            "/web/extension-api-blocker",
            "/web/ext-firewall",
        )
        if not any(path.startswith(prefix) for prefix in blocked_prefixes):
            return False
        self._send_json(
            {
                "error": "extension_era_routes_retired",
                "message": "Solace Browser is a native-sidebar product. Extension-era routes are permanently disabled.",
                "port": YINYANG_PORT,
            },
            410,
        )
        return True

