    # --- DELETE routing ---
    def do_DELETE(self) -> None:
        path = self.path.split("?")[0]
        if self._reject_extension_era_route(path):
            return
        if path.startswith("/api/v1/browser/schedules/"):
            schedule_id = path[len("/api/v1/browser/schedules/"):]
            self._handle_schedule_delete(schedule_id)
        elif path.startswith("/api/v1/oauth3/tokens/"):
            token_id = path[len("/api/v1/oauth3/tokens/"):]
            self._handle_oauth3_revoke(token_id)
        elif re.match(r"^/api/v1/sessions/[^/]+$", path):
            session_id = path.split("/")[-1]
            self._handle_session_delete(session_id)
        elif re.match(r"^/api/v1/browser/sessions/[^/]+$", path):
            session_id = path.split("/")[-1]
            self._handle_session_delete(session_id)
        elif re.match(r"^/api/v1/profiles/[^/]+$", path):
            profile_id = path.split("/")[-1]
            self._handle_profiles_delete(profile_id)
        elif path == "/api/v1/apps/favorites":
            self._handle_apps_favorites_delete()
        elif re.match(r"^/api/v1/labels/[^/]+$", path):
            label_id = path.split("/")[-1]
            self._handle_label_delete(label_id)
        elif re.match(r"^/api/v1/memory/[^/]+$", path):
            key = path.split("/")[-1]
            self._handle_memory_delete(key)
        elif re.match(r"^/api/v1/actions/[^/]+/cancel$", path):
            action_id = path.split("/")[-2]
            self._handle_action_cancel(action_id)
        elif m := re.match(r"^/api/v1/apps/([^/]+)/activate$", path):
            self._handle_app_deactivate(m.group(1))
        elif m := re.match(r"^/api/v1/apps/([^/]+)/install$", path):
            self._handle_app_uninstall_by_id(m.group(1))
        elif m := re.match(r"^/api/v1/apps/([^/]+)$", path):
            self._handle_custom_app_delete(m.group(1))
        elif path == "/api/v1/chat/history":
            self._handle_chat_history_delete()
        elif re.match(r"^/api/v1/notifications/[^/]+$", path):
            notif_id = path.split("/")[-1]
            self._handle_notification_dismiss(notif_id)
        elif re.match(r"^/api/v1/reports/scheduled/[^/]+$", path):
            report_id = path.split("/")[-1]
            self._handle_reports_scheduled_delete(report_id)
        # --- Twin Browser Dashboard — Task 022 ---
        elif m := re.match(r"^/api/v1/twin/queue/([^/]+)$", path):
            self._handle_twin_queue_cancel(m.group(1))
        # --- OAuth3 Consent UI — Task 024 ---
        elif re.match(r"^/api/v1/oauth3/consented/[^/]+$", path):
            grant_id = path.split("/")[-1]
            self._handle_oauth3_consent_revoke(grant_id)
        # --- Task 032: Quick Actions Menu — DELETE custom action ---
        elif re.match(r"^/api/v1/quick-actions/[^/]+$", path):
            action_id = path.split("/")[-1]
            self._handle_quick_actions_delete(action_id)
        # --- Browser Profile Manager — Task 025 ---
        elif re.match(r"^/api/v1/browser/profiles/[^/]+$", path):
            profile_id = path.split("/")[-1]
            self._handle_browser_profiles_delete(profile_id)
        # --- Session Replay Viewer — Task 027 ---
        elif re.match(r"^/api/v1/replay/sessions/[^/]+$", path):
            replay_id = path.split("/")[-1]
            self._handle_replay_session_delete(replay_id)
        # --- Keyboard Shortcuts Panel — Task 028 ---
        elif re.match(r"^/api/v1/keyboard-shortcuts/[^/]+$", path):
            shortcut_id = path.split("/")[-1]
            self._handle_keyboard_shortcut_delete(shortcut_id)
        # --- Task 034: Budget Alert System ---
        elif re.match(r"^/api/v1/budget/alert-rules/[^/]+$", path):
            alert_id = path.split("/")[-1]
            self._handle_budget_alert_rule_delete(alert_id)
        # --- Task 035: Multi-Tab Manager ---
        elif re.match(r"^/api/v1/tabs/[^/]+$", path):
            tab_id = path.split("/")[-1]
            self._handle_tab_delete(tab_id)
        # --- Task 036: URL Bookmarks Manager ---
