    def _runtime_snapshot_payload(self) -> dict:
        with _SESSIONS_LOCK:
            sessions = [
                {
                    "session_id": sid,
                    "url": sess.get("url", ""),
                    "profile": sess.get("profile", ""),
                    "pid": sess.get("pid", 0),
                    "alive": self._is_session_alive(int(sess.get("pid", 0))),
                    "started_at": sess.get("started_at", 0),
                }
                for sid, sess in _SESSIONS.items()
            ]
        try:
            onboarding = json.loads(ONBOARDING_PATH.read_text())
        except (FileNotFoundError, json.JSONDecodeError):
            onboarding = {"completed": False, "mode": None}
        return {
            "status": "ok",
            "compatibility_mode": True,
            "source": "yinyang-runtime",
            "runtime": {
                "port": YINYANG_PORT,
                "version": _SERVER_VERSION,
                "sidebar": "pinned-yinyang",
                "onboarding": onboarding,
                "sessions": sessions,
                "session_count": len(sessions),
                "health": {
                    "status": "ok",
                    "uptime_seconds": int(time.time() - _SERVER_START_TIME),
                },
            },
            "limitations": [
                "Hub-owned runtime snapshot; full Chromium DOM automation routes are not yet wired through this server.",
            ],
        }

    def _handle_aria_snapshot(self) -> None:
        payload = self._runtime_snapshot_payload()
        payload["snapshot_type"] = "aria"
        payload["tree"] = {
            "role": "application",
            "name": "Solace Browser Runtime",
            "children": [
                {"role": "banner", "name": "Solace Hub starts first"},
                {"role": "complementary", "name": "Yinyang AI Assistant Sidebar"},
                {"role": "main", "name": "Browser workspace"},
            ],
        }
        self._send_json(payload)

    def _handle_dom_snapshot(self) -> None:
        payload = self._runtime_snapshot_payload()
        payload["snapshot_type"] = "dom"
        payload["document"] = {
            "nodeName": "BODY",
            "children": [
                {"nodeName": "HEADER", "text": "Solace Hub starts first"},
                {"nodeName": "ASIDE", "text": "Yinyang AI Assistant Sidebar"},
                {"nodeName": "MAIN", "text": "Browser workspace"},
            ],
        }
        self._send_json(payload)

    def _handle_page_snapshot(self) -> None:
        payload = self._runtime_snapshot_payload()
        payload["snapshot_type"] = "page"
        payload["page"] = {
            "title": "Solace Browser Runtime",
            "start_url": _localized_solaceagi_url(DEFAULT_BROWSER_START_URL),
            "current_sessions": payload["runtime"]["sessions"],
        }
        self._send_json(payload)

    def _handle_locale_get(self) -> None:
        settings = _load_settings()
        locale = _current_runtime_locale(settings)
        self._send_json(
            {
                "locale": locale,
                "direction": _runtime_locale_direction(locale),
                "supported_locales": list(SUPPORTED_RUNTIME_LOCALES),
                "dashboard_url": _localized_solaceagi_url(DEFAULT_BROWSER_START_URL, locale),
            }
        )

    def _handle_locale_set(self) -> None:
        body = self._tracker_body()
        if body is None:
            return
        settings = _load_settings()
        locale = _normalize_runtime_locale(body.get("locale", "en"))
        settings["locale"] = locale
        _save_settings(settings)
        self._send_json(
            {
                "ok": True,
                "locale": locale,
                "direction": _runtime_locale_direction(locale),
                "dashboard_url": _localized_solaceagi_url(DEFAULT_BROWSER_START_URL, locale),
            }
        )

    def _handle_yinyang_locale_asset(self, locale: str) -> None:
        locale_name = _normalize_runtime_locale(locale)
        locale_path = YINYANG_LOCALES_DIR / f"{locale_name}.json"
        if not locale_path.exists():
            locale_path = YINYANG_LOCALES_DIR / "en.json"
        try:
            body = locale_path.read_bytes()
        except OSError as error:
            self._send_json({"error": "locale_unavailable", "detail": str(error)}, 500)
            return
        self.send_response(200)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Cache-Control", "no-store")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

