    def _handle_hub_screenshot(self) -> None:
        if not self._check_auth():
            return
        body = self._read_json_body()
        if body is None:
            return
        filename = str(body.get("filename", "")).strip() or f"hub-window-{int(time.time())}.png"
        if not filename.endswith(".png"):
            filename = f"{filename}.png"
        capture = self._capture_hub_window_artifact(filename)
        if capture is None:
            self._send_json(
                {
                    "error": "hub_window_not_visible",
                    "message": "No visible Solace Hub window was available for capture.",
                },
                404,
            )
            return
        self._send_json({"status": "ok", **capture})

    def _handle_hub_action(self) -> None:
        if not self._check_auth():
            return
        body = self._read_json_body()
        if body is None:
            return
        name = str(body.get("name", "")).strip() or str(body.get("target", "")).strip()
        if not name:
            self._send_json({"error": "name or target is required"}, 400)
            return
        action_name = str(body.get("action", "click")).strip() or "click"
        role_value = body.get("role")
        role = str(role_value).strip() if isinstance(role_value, str) and role_value.strip() else None
        if self._handle_hub_builtin_action(name=name, action_name=action_name):
            return
        result = self._hub_invoke_action(name=name, action_name=action_name, role=role)
        status_code = 200 if result.get("status") == "ok" else 404 if result.get("status") == "not_found" else 409
        self._send_json(result, status_code)

    def _handle_hub_builtin_action(self, *, name: str, action_name: str) -> bool:
        if action_name != "click":
            return False
        normalized = re.sub(r"[^a-z0-9]+", "", name.lower())
        if normalized in {
            "openbrowserbutton",
            "btnopenbrowser",
            "openbrowser",
            "opensolacebrowser",
        }:
            self._launch_controlled_browser_session(
                url=DEFAULT_BROWSER_START_URL,
                profile="default",
                mode="standard",
                session_name_raw="",
                head_hidden=False,
                source="hub-ui",
                allow_duplicate=False,
            )
            return True
        if normalized in {
            "openaccountbutton",
            "btnopenaccount",
            "openaccount",
            "signincreateaccount",
            "signincreatefreeaccountoptional",
        }:
            self._launch_controlled_browser_session(
                url="https://solaceagi.com/register",
                profile="default",
                mode="standard",
                session_name_raw="",
                head_hidden=False,
                source="hub-ui",
                allow_duplicate=False,
            )
            return True
        return False

