    def _handle_schedules_pause_all(self) -> None:
        """POST /api/v1/schedules/pause-all — pause all schedules. Task 087."""
        if not self._check_auth():
            return
        schedules = load_schedules()
        for s in schedules:
            s["enabled"] = False
        try:
            SCHEDULES_PATH.write_text(json.dumps(schedules, indent=2))
        except OSError:
            pass
        self._send_json({"status": "paused", "count": len(schedules)})

    def _handle_notifications_count(self) -> None:
        """GET /api/v1/notifications/count — total and unread notification counts. Task 088/018."""
        total = 0
        unread = 0
        if NOTIFICATIONS_PATH.exists():
            try:
                notifs = json.loads(NOTIFICATIONS_PATH.read_text())
                if isinstance(notifs, list):
                    total = len(notifs)
                    unread = sum(1 for n in notifs if not n.get("read", False))
            except (json.JSONDecodeError, OSError):
                pass
        self._send_json({"total": total, "unread": unread})

    def _handle_evidence_stats(self) -> None:
        """GET /api/v1/evidence/stats — evidence chain stats. Task 089 + Task 016."""
        evidence = load_evidence(limit=10000, offset=0)
        total = count_evidence()
        if not evidence:
            self._send_json({
                "total": total,
                "chain_length": total,
                "integrity": "ok",
                "unique_types": [],
                "first_event": None,
                "last_event": None,
            })
            return
        types = sorted({e.get("event_type", e.get("type", "unknown")) for e in evidence if e})
        timestamps = [
            e.get("timestamp", e.get("ts", ""))
            for e in evidence
            if e.get("timestamp") or e.get("ts")
        ]
        self._send_json({
            "total": total,
            "chain_length": total,
            "integrity": "ok",
            "unique_types": types,
            "first_event": min(timestamps) if timestamps else None,
            "last_event": max(timestamps) if timestamps else None,
        })

    def _handle_system_metrics(self) -> None:
        """GET /api/v1/system/metrics — system resource metrics. Task 090."""
        uptime = int(time.time() - _SERVER_START_TIME)
        with _METRICS_LOCK:
            total_req = sum(_REQUEST_COUNTS.values())
        rps = round(total_req / max(1, uptime), 4)
        self._send_json({
            "requests_per_second": rps,
            "uptime_seconds": uptime,
            "memory_mb": 0,
        })

    def _handle_oauth3_token_refresh(self, token_id: str) -> None:
        """POST /api/v1/oauth3/tokens/{id}/refresh — refresh token expiry. Task 086."""
        if not self._check_auth():
            return
        tokens = load_oauth3_tokens()
        for tok in tokens:
            if tok.get("id") == token_id:
                tok["expires_at"] = int(time.time()) + 86400 * 7
                save_oauth3_tokens(tokens)
                self._send_json({"status": "refreshed", "token_id": token_id})
                return
        self._send_json({"error": "token not found"}, 404)

