    # ---------------------------------------------------------------------------
    # Task 063 — History Search handlers
    # ---------------------------------------------------------------------------

    def _handle_history_list(self) -> None:
        """GET /api/v1/history/entries — list history entries."""
        with _HISTORY_LOCK:
            entries = [dict(e) for e in _HISTORY_ENTRIES]
        self._send_json({"entries": entries, "total": len(entries)})

    def _handle_history_add(self) -> None:
        """POST /api/v1/history/entries — add or update history entry (auth required)."""
        if not self._check_auth():
            return
        body = self._read_json_body()
        if body is None:
            return
        url_hash = str(body.get("url_hash", "")).strip()
        if not url_hash or len(url_hash) != 64:
            self._send_json({"error": "url_hash must be SHA-256 (64 hex chars)"}, 400)
            return
        title = str(body.get("title", "")).strip()
        if len(title) > 512:
            self._send_json({"error": "title max 512 chars"}, 400)
            return
        content_type = str(body.get("content_type", "page")).strip()
        if content_type not in HISTORY_CONTENT_TYPES:
            self._send_json({"error": f"content_type must be one of {HISTORY_CONTENT_TYPES}"}, 400)
            return
        duration_ms = body.get("duration_ms", 0)
        try:
            duration_ms = int(duration_ms)
        except (TypeError, ValueError):
            duration_ms = 0
        if duration_ms < 0:
            self._send_json({"error": "duration_ms must be >= 0"}, 400)
            return
        now = datetime.now(timezone.utc).isoformat()
        with _HISTORY_LOCK:
            existing = next((e for e in _HISTORY_ENTRIES if e["url_hash"] == url_hash), None)
            if existing is not None:
                existing["visit_count"] += 1
                existing["visited_at"] = now
                entry = dict(existing)
            else:
                if len(_HISTORY_ENTRIES) >= MAX_HISTORY_ENTRIES:
                    _HISTORY_ENTRIES.pop(0)
                entry = {
                    "entry_id": "hist_" + uuid.uuid4().hex,
                    "url_hash": url_hash,
                    "title": title,
                    "content_type": content_type,
                    "visit_count": 1,
                    "visited_at": now,
                    "duration_ms": duration_ms,
                }
                _HISTORY_ENTRIES.append(entry)
        self._send_json({"status": "recorded", "entry": entry}, 201)

    def _handle_history_clear(self) -> None:
        """DELETE /api/v1/history/entries — clear all history (auth required)."""
        if not self._check_auth():
            return
        with _HISTORY_LOCK:
            count = len(_HISTORY_ENTRIES)
            _HISTORY_ENTRIES.clear()
        self._send_json({"status": "cleared", "count": count})

    def _handle_history_search(self) -> None:
        """POST /api/v1/history/search — search history by title/hash (auth required)."""
        if not self._check_auth():
            return
        body = self._read_json_body()
        if body is None:
            return
        query = str(body.get("query", "")).strip().lower()
        limit = body.get("limit", 50)
        try:
            limit = int(limit)
        except (TypeError, ValueError):
            limit = 50
        limit = min(max(limit, 1), 500)
        with _HISTORY_LOCK:
            if query:
                results = [dict(e) for e in _HISTORY_ENTRIES if query in e.get("title", "").lower() or query in e["url_hash"]]
            else:
                results = [dict(e) for e in _HISTORY_ENTRIES]
        results = results[:limit]
        self._send_json({"results": results, "total": len(results), "query": query})

    def _handle_history_stats(self) -> None:
        """GET /api/v1/history/stats — history statistics."""
        with _HISTORY_LOCK:
            total = len(_HISTORY_ENTRIES)
            by_type: dict[str, int] = {t: 0 for t in HISTORY_CONTENT_TYPES}
            total_visits = 0
            for e in _HISTORY_ENTRIES:
                ct = e.get("content_type", "page")
                if ct in by_type:
                    by_type[ct] += 1
                total_visits += e.get("visit_count", 1)
        self._send_json({"total_entries": total, "total_visits": total_visits, "by_content_type": by_type})

    def _handle_history_top_domains(self) -> None:
        """GET /api/v1/history/top-domains — top domains by visit count."""
        with _HISTORY_LOCK:
            entries = list(_HISTORY_ENTRIES)
        domain_counts: dict[str, int] = {}
        for e in entries:
            dh = e["url_hash"][:16]
            domain_counts[dh] = domain_counts.get(dh, 0) + e.get("visit_count", 1)
        sorted_domains = sorted(domain_counts.items(), key=lambda x: x[1], reverse=True)[:20]
        result = [{"domain_hash": dh, "visit_count": vc} for dh, vc in sorted_domains]
        self._send_json({"domains": result, "total": len(result)})

    def _handle_theme_customizer_apply_preset(self, preset_id: str) -> None:
        """POST /api/v1/theme/customizer/preset/{preset_id} — apply preset (auth required)."""
        if not self._check_auth():
            return
        preset = next((p for p in THEME_PRESETS if p["preset_id"] == preset_id), None)
        if preset is None:
            self._send_json({"error": f"preset not found: {preset_id}"}, 404)
            return
        with _THEME_CUSTOMIZER_LOCK:
            _CURRENT_THEME_CUSTOMIZER["preset_id"] = preset["preset_id"]
            _CURRENT_THEME_CUSTOMIZER["accent_color"] = preset["accent"]
            _CURRENT_THEME_CUSTOMIZER["bg_color"] = preset["bg"]
            _CURRENT_THEME_CUSTOMIZER["text_color"] = preset["text"]
            _CURRENT_THEME_CUSTOMIZER["font_size"] = preset["font_size"]
            _CURRENT_THEME_CUSTOMIZER["custom"] = False
            theme = dict(_CURRENT_THEME_CUSTOMIZER)
        self._send_json({"status": "applied", "theme": theme})

    # ---------------------------------------------------------------------------
    # Task 064 — Media Downloader handlers
    # ---------------------------------------------------------------------------

    def _handle_media_queue_list(self) -> None:
        """GET /api/v1/media/queue — list download queue."""
        with _MEDIA_LOCK:
            queue = [dict(item) for item in _MEDIA_QUEUE]
        self._send_json({"queue": queue, "total": len(queue)})

    def _handle_media_queue_add(self) -> None:
        """POST /api/v1/media/queue — add to download queue (auth required)."""
        if not self._check_auth():
            return
        body = self._read_json_body()
        if body is None:
            return
        url = str(body.get("url", "")).strip()
        if not url:
            self._send_json({"error": "url is required"}, 400)
            return
        url_hash = hashlib.sha256(url.encode()).hexdigest()
        media_type = str(body.get("media_type", "")).strip()
        if media_type not in MEDIA_TYPES:
            self._send_json({"error": f"media_type must be one of {MEDIA_TYPES}"}, 400)
            return
        filename = str(body.get("filename", "")).strip()
        if len(filename) > 256:
            self._send_json({"error": "filename max 256 chars"}, 400)
            return
        file_size_bytes = body.get("file_size_bytes", 0)
        try:
            file_size_bytes = int(file_size_bytes)
        except (TypeError, ValueError):
            file_size_bytes = 0
        with _MEDIA_LOCK:
            if len(_MEDIA_QUEUE) >= MAX_QUEUE_SIZE:
                self._send_json({"error": f"queue full (max {MAX_QUEUE_SIZE})"}, 400)
                return
            item = {
                "item_id": "med_" + uuid.uuid4().hex,
                "url_hash": url_hash,
                "media_type": media_type,
                "filename": filename,
                "file_size_bytes": file_size_bytes,
                "status": "queued",
                "queued_at": datetime.now(timezone.utc).isoformat(),
                "completed_at": None,
            }
            _MEDIA_QUEUE.append(item)
        self._send_json({"status": "queued", "item": dict(item)}, 201)

    def _handle_media_queue_remove(self, item_id: str) -> None:
        """DELETE /api/v1/media/queue/{item_id} — remove from queue (auth required)."""
        if not self._check_auth():
            return
        with _MEDIA_LOCK:
            idx = next((i for i, it in enumerate(_MEDIA_QUEUE) if it["item_id"] == item_id), None)
            if idx is None:
                self._send_json({"error": "item not found"}, 404)
                return
            _MEDIA_QUEUE.pop(idx)
        self._send_json({"status": "removed", "item_id": item_id})

    def _handle_media_queue_complete(self, item_id: str) -> None:
        """POST /api/v1/media/queue/{item_id}/complete — mark as completed (auth required)."""
        if not self._check_auth():
            return
        with _MEDIA_LOCK:
            item = next((it for it in _MEDIA_QUEUE if it["item_id"] == item_id), None)
            if item is None:
                self._send_json({"error": "item not found"}, 404)
                return
            item["status"] = "completed"
            item["completed_at"] = datetime.now(timezone.utc).isoformat()
            result = dict(item)
        self._send_json({"status": "completed", "item": result})

    def _handle_media_stats(self) -> None:
        """GET /api/v1/media/stats — download statistics."""
        with _MEDIA_LOCK:
            total = len(_MEDIA_QUEUE)
            queued = sum(1 for it in _MEDIA_QUEUE if it["status"] == "queued")
            completed = sum(1 for it in _MEDIA_QUEUE if it["status"] == "completed")
            failed = sum(1 for it in _MEDIA_QUEUE if it["status"] == "failed")
            total_bytes = sum(it.get("file_size_bytes", 0) for it in _MEDIA_QUEUE)
        self._send_json({"total": total, "queued": queued, "completed": completed,
                         "failed": failed, "total_bytes": total_bytes})

    def _handle_media_types(self) -> None:
        """GET /api/v1/media/types — list supported media types."""
        self._send_json({"types": list(MEDIA_TYPES), "statuses": list(MEDIA_STATUSES)})

