        """GET /api/v1/interceptor/rule-types — list rule types (public)."""
        self._send_json({
            "rule_types": INTERCEPT_RULE_TYPES,
            "actions": INTERCEPT_ACTIONS,
            "methods": HTTP_METHODS_INTERCEPT,
        })

