        by_type: dict[str, int] = {}
        pdf_hashes: set[str] = set()
        for n in notes:
            nt = n.get("note_type", "")
            by_type[nt] = by_type.get(nt, 0) + 1
            if n.get("pdf_hash"):
                pdf_hashes.add(n["pdf_hash"])
        self._send_json({
            "total_notes": len(notes),
            "by_type": by_type,
            "total_pdfs": len(pdf_hashes),
        })

