        with _VIDEO_LOCK:
            downloads = list(_VIDEO_DOWNLOADS)
        total_size_bytes = sum(d.get("file_size_bytes", 0) for d in downloads)
        by_status: dict = {}
        by_quality: dict = {}
        for d in downloads:
            s = d.get("status", "")
            by_status[s] = by_status.get(s, 0) + 1
